CREATE TABLE alt_signals (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    signal_type TEXT NOT NULL,        -- 'gtrends_theme'
    theme TEXT,                       -- 'AI 软件' 等 (P9 theme，可 null 如果是个股)
    keyword TEXT NOT NULL,            -- 实际 google trends 查询词
    week_start TEXT NOT NULL,         -- 'YYYY-MM-DD' (周一)
    value INTEGER NOT NULL,           -- 0-100 (SerpAPI extracted_value)
    source TEXT NOT NULL,             -- 'serpapi'
    collected_at TEXT DEFAULT (datetime('now')),
    UNIQUE(signal_type, keyword, week_start)
);
CREATE TABLE decisions (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            date TEXT, symbol TEXT, signal TEXT,
            entry_price REAL, target_price REAL, stop_price REAL,
            reasoning TEXT, order_id TEXT,
            created_at TEXT DEFAULT (datetime('now'))
        , spy_signal TEXT, intraday_target REAL, strategy_version TEXT, no_trade_reason TEXT);
