CREATE TABLE trades (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            decision_id INTEGER,
            symbol TEXT NOT NULL,
            side TEXT NOT NULL,
            order_id TEXT,
            close_order_id TEXT,
            entry_date TEXT,
            exit_date TEXT,
            qty REAL,
            filled_qty REAL,
            fill_price REAL,
            close_fill_price REAL,
            realized_pnl REAL,
            status TEXT DEFAULT 'open',
            created_at TEXT DEFAULT (datetime('now'))
        );
CREATE TABLE watchlist (
            id INTEGER PRIMARY KEY,
            symbol TEXT,
            score INTEGER,
            old_label TEXT,
            new_signal TEXT,
            invalidation TEXT,
            explosion_catalyst TEXT,
            scan_date TEXT
        , score_narrative INTEGER, score_market_lag INTEGER, score_tailwind INTEGER, score_catalyst INTEGER, score_tradability INTEGER, score_disconfirmation INTEGER, theme TEXT, scan_price REAL, analyst_count INTEGER, avg_dollar_volume REAL);
CREATE UNIQUE INDEX idx_news_unique ON news(date, symbol, headline);
CREATE UNIQUE INDEX idx_insider_unique ON insider_transactions(date, symbol, transaction_date, direction, shares);
CREATE UNIQUE INDEX idx_signals_unique ON signals(symbol, date, headline);
CREATE UNIQUE INDEX idx_scanner_picks_uniq ON scanner_picks(symbol, scan_date);
CREATE UNIQUE INDEX idx_trades_order_id_uniq ON trades(order_id) WHERE order_id IS NOT NULL;
CREATE INDEX idx_alt_signals_theme_week ON alt_signals(theme, week_start);
