INSERT INTO "scanner_picks" VALUES(3,'ORA',123.72,'2026-05-06',10,'市场将ORA定义为传统地热能源公司，以地热发电资产估值，适用偏保守的可再生能源股框架','ORA正从纯地热电力商向「地热+储能」双轮增长平台转型：80MW/320MWh Shirk储能设施已正式投入商业运营，同时签署150MW地热供电协议服务谷歌，并通过$10亿可转债大规模募资支撑扩张。','1. Q1 2026财报中储能业务收入贡献不及预期，或管理层下调全年指引；2. NV Energy/Google地热协议出现执行延迟或取消公告','Q1 2026财报电话会议（已公告即将举行）首次披露储能板块独立营收，并确认后续储能管线规模，触发市场将ORA从单一地热股重新定价为储能+地热平台股',NULL,NULL,'filled','2026-05-06','Q1 2026财报（首次披露储能独立营收）',286.8,'GRID',197.73,NULL,NULL,NULL,NULL,-8.89099496026805463e-02,NULL,NULL,NULL,'confirmed','AI电力','公用事业现代化','ORA 的储能业务规模相对 Fluence、Tesla Energy 等头部玩家可能仍是 sub-scale 二线玩家，把它讲成"储能+地热平台股"可能忽略了储能业务毛利率结构性低于地热（merchant 敞口 vs contracted PPA），独立披露反而有可能暴露稀释问题。地热主业的 resource degradation（老电站资源温度/压力自然衰减）历史上 may 被 capex 资本化掩盖，maintenance capex 算成 growth capex 时会系统性高估 EBITDA。Puna 单一资产集中度（2018 Kilauea 火山喷发后产能未完全恢复）+ 肯尼亚 Olkaria 的 FX 与应收账款风险（KenyaPower 历史上有支付延迟）属于 SoTP 估值未充分反映的尾部风险。IRA 地热 PTC 历史上对增长 IRR 至关重要，地热游说力量结构性弱于太阳能/风能，2026 选举周期后选择性政策回滚是结构性风险。历史 pattern：Bloom Energy/Sunnova/Calpine 等"contracted + 新业务"故事公司曾多次在 narrative 阶段 rerate up，后因执行 mishap 或政策变化非线性 de-rate。','地热 resource degradation 资本化掩盖 - 监测 10-K 中 electricity segment capex 中 development vs enhancement/makeup wells 拆分比例 + 单位 MWh 产出趋势; 肯尼亚 Olkaria 应收 & FX 风险 - 监测 trade receivables aging 中 Kenya Power 应收 + KES/USD 汇率 + 任何关于 East Africa 资产 impairment 的语言; IRA 地热 PTC 政策风险 - 监测 House Ways & Means 关于 45U/48E 修订提案进度 + Treasury 关于 geothermal PTC 实施细则','tentative',NULL,NULL,'2026-05-06','2026-05-06',123.72,123.72,'early_filled',286.8,81,'巽/离','用生体',42,'2004-11-11',NULL,NULL,NULL,NULL,NULL,NULL,11,1.33398421664999991e+08);
INSERT INTO "scanner_picks" VALUES(5,'CPK',127.903333,'2026-05-06',9,'市场将CPK定义为稳健的高股息公用事业股，核心价值在于持续分红能力','公司接连任命首席转型官（Chief Transformation Officer）并更换CFO，显示管理层正主动推进战略转型而非维持现状；分红连续提升7.3%也表明现金流仍在改善。','1. 2026年5月7日Q1财报电话会议中管理层未披露转型路线图或量化目标，''转型''停留于职位名称层面；2. 后续季度分红增速逆转或归母净利润出现下滑，说明转型消耗利润而非创造价值。','2026年5月7日Q1 2026财报电话会议上，新任首席转型官首次公开阐述具体转型战略并给出可量化的财务指引，触发市场对公司成长框架的重新定价。',NULL,NULL,'filled','2026-05-06','Q1 2026财报',286.8,'GRID',197.73,NULL,NULL,NULL,NULL,-5.69440223533343825e+00,NULL,NULL,NULL,'neutral','分析师重定价','公用事业现代化','受规管水/天然气公用事业的"转型故事"在历史上较少真正改变 PE 估值中枢——州 PUC 决定的允许 ROE 和 rate base 增长通常才是估值锚。新任 CTO 给出的"可量化指引"可能仍受制于监管 lag 和 capex disallowance 风险，市场用 DCF 视角看穿后有可能回归板块均值区间。同时 CPK 体量偏小，即便讲出 AI/数字化转型故事，也可能难以吸引基本面买家从 AWK/WTRG 这类龙头切换过来——小盘公用事业的 multiple expansion 在历史样本中结构性偏弱。','多州费率裁决 disallowance - 监测 DE/MD/FL PSC rate case order 中 capex 被剔除比例; 天然气资产监管退坡 - 监测各州 building electrification / gas ban 立法进度; 转型 capex 拉低短期 EPS - 监测 Q1/Q2 capex guide 是否超过 D&A+30%','tentative',NULL,NULL,'2026-05-06','2026-05-06',127.903333,127.903333,'early_filled',286.8,60,'离/乾','体克用',34,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,5,18115651.04);
INSERT INTO "scanner_picks" VALUES(7,'WTRG',37.736875,'2026-05-06',9,'市场将WTRG定义为传统高收益分红水务公用事业股，以稳定股息和监管保护为核心价值主张。','WTRG正在通过与American Water的重大合并交易实现结构性转型，该合并已获肯塔基公共服务委员会批准并通过股东大会投票，标志着公司从区域性水务运营商向全国性规模平台的质变；与此同时，公司同步推进小型市政收购（Greenville Municipal Water）和Q4盈利超预期，呈现出多线并进的增长叙事。','1. 合并交易遭遇关键监管阻力或终止，任何州级或联邦层面的否决公告均构成直接失效信号；2. Q1 2026财报确认分析师预期的盈利下滑，且管理层下调全年指引，证明增长叙事仅为并购驱动的一次性效应。','American Water与WTRG合并最终交割完成，市场将被迫用全国性规模水务平台框架重新对WTRG定价，估值倍数将向更大体量可比标的靠拢。',NULL,NULL,'filled','2026-05-07','Q1 2026财报（并购推进+业绩验证）',286.8,'GRID',197.73,NULL,NULL,NULL,NULL,-3.94011162821510163e+00,NULL,NULL,NULL,'neutral','公用事业现代化','分析师重定价','大型水务并购（若为 AWK + WTRG 情景）可能面临较高的反垄断和州 PUC 审批风险——历史上 AWK 自身的多州收购就遭遇过 disallowance，跨州整合两大水务巨头有可能触发联邦层面审查。即便交割完成，收购方溢价支付的整合通常需要数年才能体现 synergy，短期 deal premium 可能已部分 priced in。"全国性平台估值倍数"的预期或许偏乐观——可比标的的估值差距未必足以支撑显著的 rerate 空间，市场对水务并购的 multiple expansion 历史上保持 skepticism。','FTC/DOJ 反垄断审查阻断 - 监测 HSR filing 二次审查和州 AG 介入; 州 PUC 不批准 change of control - 监测 PA/NC/IL/OH 等核心州 PUC 决议; 利率敏感性 - 监测 10Y Treasury 突破 4.75% 对受规管公用事业整体估值压制','tentative',NULL,NULL,'2026-05-06','2026-05-06',37.736875,37.736875,'early_filled',286.8,60,'离/乾','体克用',45,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,5,74964400.55);
INSERT INTO "scanner_picks" VALUES(8,'LZ',6.17,'2026-05-06',9,'市场将LZ定义为面临AI颠覆风险的传统在线法律文件/DIY法律服务平台，增长乏力、盈利承压。','LZ正从''AI受害者''转型为''AI基础设施使用者''：已与Anthropic（Claude）、OpenAI（ChatGPT）、GoDaddy（Open Agentic Web）达成多项AI集成合作，同时订阅业务增长依然强劲。这一转型信号在近期新闻中多次、跨平台出现。','1. Q1 2026财报（2026-05-06发布）显示订阅收入环比下滑，或AI产品无法贡献可量化收入指引；2. Anthropic/OpenAI/GoDaddy任一合作终止或降级，表明AI集成为营销噱头而非战略绑定。','2026-05-06 Q1财报超预期，且管理层首次披露AI集成（Claude/ChatGPT渠道）带来的具体订阅转化数据或收入增量，触发市场重新定价其AI平台属性。',NULL,NULL,'filled','2026-05-06','Q1 2026财报（AI平台转型验证）',286.8,'GRID',197.73,NULL,NULL,NULL,NULL,-9.4003216760471524e+00,NULL,NULL,NULL,'neutral','AI软件','分析师重定价','LegalZoom 的核心业务（在线公司注册）是高度商品化的引流漏斗，AI 集成可能是双刃剑——通用 LLM 直接生成 LLC 文件和 operating agreement 的能力有可能绕过 LegalZoom 渠道，使其从"AI 受益者"转向"AI 被颠覆者"的叙事一侧。即便管理层披露 AI 转化数据，订阅 ARPU 长期面临 Rocket Lawyer、Bonsai 等更轻工具的压制，subscription mix 提升未必能换来 SaaS 估值倍数。历史 pattern 上，LZ 每次讲"平台化"故事（2021 IPO 时、2023 SMB 顾问故事）后，股价倾向于在数个季度内回到原点——市场对其平台叙事的 durability 存在持续怀疑。','AI 直接绕过形成渠道 disintermediation - 监测 ChatGPT/Claude LLC 注册类 prompt 使用增长 + Stripe Atlas 等 AI 原生竞品 ARR; Formation volume 同比下滑 - 监测美国月度 new business application（Census BFS 数据）; Subscription churn 上升 - 监测季度 subscription unit retention 是否跌破 75%','tentative',NULL,NULL,'2026-05-06','2026-05-06',6.17,6.17,'early_filled',286.8,57,'离/乾','体克用',30,'2021-06-30',NULL,NULL,NULL,NULL,NULL,NULL,6,15619435.755);
INSERT INTO "scanner_picks" VALUES(9,'VRRM',14.38,'2026-05-06',9,'传统交通执法与政府服务公司，依赖红灯摄像头和电子收费系统获取稳定但低增长的政府合同收入','公司一方面推出AI驱动的车载虚拟代理产品AutoKinex™，向车载数字体验赛道延伸；另一方面连续落地$9.98亿纽约市五年合同及夏威夷十年合同，政府平台规模快速扩张，同时受邀出席Morgan Stanley TMT（科技/媒体/电信）会议，暗示外部对公司定位的重新归类。','1. Q1 2026财报继续低于预期，且NYC/$998M合同收入确认节奏明显滞后于市场预期；2. AutoKinex™产品在租车行业未获实质性采购合同，停留于发布公告层面无商业化跟进。','Q1 2026财报电话会议中管理层首次披露NYC大合同收入确认进度及AutoKinex™客户签约数据，触发分析师重新建模上调目标价。',3.85,-73.23,'exited','2026-05-06','Q1 2026财报（NYC合同收入确认+AutoKinex）',286.8,'GRID',197.73,'client_contract_loss','Avis合同终止(2026-09生效)，-135~145M年化收入，分析师集体降级。Bear thesis警告政治风险但遗漏客户集中度风险。',NULL,NULL,-2.98559358841425392e+00,'{"2026-05-29": 4.510000228881836, "2026-06-01": 4.889999866485596, "2026-06-02": 4.159999847412109, "2026-06-03": 4.130000114440918, "2026-06-04": 4.309999942779541, "2026-06-05": 4.309999942779541, "2026-06-08": 4.179999828338623}',4.89,8.57,'invalidated','分析师重定价','公用事业现代化','自动化交通执法是高度政治敏感业务，NYC 大合同的收入确认节奏可能受市政预算和公众反对运动影响——历史上 Chicago、Houston 都出现过 camera program 中途叫停或缩减的案例。AutoKinex 客户签约即便公布，从 contract win 到 revenue recognition 通常需要较长周期，分析师上调目标价有可能在执行落地阶段被打脸。VRRM 的 PE 大股东历史上有阶段性减持动作，rerate 阶段有时会对应 secondary offering 的供给压制——这是市场对其 ownership overhang 的结构性担忧。','城市级 camera program 政治反弹 - 监测 NYC City Council 和 state legislature 关于 speed camera 立法变更; PE/insider 二级市场减持 - 监测 13D/G 持仓变化和 Form 144 申报; DOJ/州检察长隐私诉讼 - 监测 ACLU 等组织对 license plate reader 业务起诉进展','thesis_invalidated_external','missing_customer_concentration_risk',NULL,'2026-05-06','2026-05-06',14.38,14.38,'early_filled',286.8,43,'兑/坤','体生用',52,'2017-03-24',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(10,'CSW',274.24,'2026-05-06',9,'市场将CSW Industrials定义为一家评级保守（平均''Hold''）的中型工业品公司，主营承包商解决方案，缺乏明确上行催化剂。','多家机构投资者在同一时间窗口密集建仓（Congress Asset Management 6500万美元、Jacobson & Schmitt 1834万美元、Allspring 140,530股），叠加公司主动将季度股息上调11%至每股0.30美元并在Q4回购3500万美元股票，内外部资本认可出现同步抬升。','1. CEO大额减持持续扩大（目前已有$430,155减持记录），或其他高管跟进卖出；2. 分析师共识评级未能从''Hold''上调，机构建仓后季度内出现减仓公告。','下一季财报（FY2027 Q1）营收/利润超预期，触发分析师从''Hold''集体上调至''Buy''，推动市场对承包商解决方案板块重新定价。',NULL,NULL,'filled','2026-05-21','Q财报',286.8,'GRID',197.73,NULL,NULL,NULL,NULL,-2.53427343023560913e+00,NULL,NULL,NULL,'neutral','分析师重定价',NULL,'CSW 过去三年已经从工业品折扣股 rerate 到接近板块上沿，分析师"Hold→Buy"的边际空间可能已被部分透支——sell side 集体上调在 cycle 后期历史上更像滞后跟随而非催化剂起点。承包商解决方案板块的可比标的（WMS、AAON、ATKR）正在从 cycle peak multiple 回落，CSW 在比较组中的相对位置显得偏高。建筑+HVAC 渠道在高利率住宅环境下面临 destocking 风险，FY27 Q1 即便 beat，也存在 "buy the rumor sell the news" 的可能性。','住宅 HVAC/管道渠道 destocking - 监测 Ferguson/Watsco 季度同店和库存周转天数; 收购整合摊销侵蚀 GAAP EPS - 监测季度 acquisition-related amortization 占比是否>15%; 估值溢价回归板块均值 - 监测 NTM P/E 与 WMS/AAON 价差，目前>30% 溢价','tentative',NULL,NULL,'2026-05-06','2026-05-06',274.24,274.24,'early_filled',286.8,75,'坎/震','用生体',26,'2015-09-30',NULL,NULL,NULL,NULL,NULL,NULL,7,38920773.56);
INSERT INTO "scanner_picks" VALUES(11,'ARLO',1.35900001525878906e+01,'2026-05-11',10,'市场将 Arlo 定义为智能家居安防摄像头硬件公司，以设备销售驱动营收','Arlo 完成收购 Aloe Care Health，将 SaaS 平台延伸至医疗警报与老年居家护理赛道；与此同时，订阅收入同比激增 39%，ARR 与付费用户数均保持 20%+ y/y 增长，公司已实质性转型为订阅服务平台。','1. Q1 2026（5月7日财报）付费订阅用户增速跌破 15% y/y，或 ARR 增长明显放缓；2. Aloe Care Health 整合后出现大额亏损且管理层下调协同预期或撤回指引。','2026年5月7日 Q1 财报发布，若订阅收入持续加速且 Aloe Care Health 贡献首次并入数字并附上盈利路径指引，将推动市场将估值框架从硬件 P/S 切换至 SaaS ARR 倍数，触发重新定价。',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-6.76968407626363,NULL,NULL,NULL,'confirmed','AI软件','行业重分类','Arlo 的"硬件向 SaaS 转型"叙事已讲了多年，订阅增长可能仍难以摆脱硬件 ASP 持续下滑（Ring/Wyze/eufy 价格战）的拖累，市场最终 blend 估值有可能仍接近硬件 P/S 而非纯 SaaS。Aloe Care Health 是老年监护小众市场，规模化路径尚不清晰，初次并表数字可能占总营收比例有限，象征意义或许大于估值意义。Amazon Ring 在 Alexa+ AI 时代具备原生集成优势，Arlo 在智能家居生态中的位置可能正在边缘化——市场对其 ecosystem moat 的 durability 存在担忧。','硬件 ASP 持续下滑 - 监测季度 device revenue / device units shipped 是否同比下滑>10%; Verisure 合作终止/续约风险 - 监测欧洲分销合作合同到期时间和续约披露; Amazon Ring 生态挤压 - 监测 Amazon Q1/Q2 device segment 披露中 Ring 增速','tentative',NULL,NULL,'2026-05-11','2026-05-18',1.35900001525878906e+01,12.92,'late_fill',275.7,25,'兑/巽','用克体',65,'2018-08-03',NULL,NULL,NULL,NULL,NULL,NULL,5,16826546.9327);
INSERT INTO "scanner_picks" VALUES(12,'AGYS',6.9089996337890625e+01,'2026-05-11',10,'市场将Agilysys定义为一家专注于酒店业的传统垂直软件供应商，提供POS和物业管理系统等存量型工具。','公司在2026年INSPIRE年度用户大会上一次性推出超过30项AI驱动新功能和软件模块，会议出席人数同比增长26%创历史记录；同期公司股价单日上涨5.8%，而GF Value显示市价仍较内在价值折价约44%。','1. 2026年5月18日Q4财报显示订阅/经常性收入增速放缓或毛利率收窄，AI功能未能转化为ARR增量；2. 新客户签约节奏明显放缓（低于当前新闻中展示的澳大利亚、菲律宾、英国多地扩张态势）。','2026年5月18日Q4财报中管理层明确披露AI模块带来的新增ARR或订阅收入占比，触发分析师上调目标价并推动市价向GF Value($119.42)靠拢。',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,2.52858621315661515e+01,NULL,NULL,NULL,'confirmed','AI软件','分析师重定价','Agilysys 的核心客户是赌场和酒店 PMS 系统，AI 模块可能面临 Oracle Opera Cloud、Cloudbeds 等更大平台的捆绑销售压力，新增 ARR 占比即便披露，也有可能被解读为"低基数效应"而非结构性放量。AGYS 当前 forward P/E 显得处于较高水位，远超 GuruFocus GF Value——但 GF Value 基于历史均值的方法对成长股通常偏低，市场未必用该 anchor 定价；不过即便剔除 GF Value，纯成长股 P/E 也已站在 historical 上沿。酒店行业 IT 支出在 RevPAR 放缓周期下有可能面临冻结，订阅模式未必能完全对冲实施收入下滑。','Oracle Hospitality 反扑 - 监测 Oracle Opera Cloud 季度新签赌场/酒店客户数; 赌场客户 IT 预算冻结 - 监测 MGM/Caesars/Wynn capex guide 中 technology 分项; 实施收入下滑拖累总营收 - 监测季度 services revenue YoY 是否转负','tentative',NULL,NULL,'2026-05-11','2026-05-18',6.9089996337890625e+01,69.1,'late_fill',275.7,25,'离/坎','用克体',48,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,6,31728045.36);
INSERT INTO "scanner_picks" VALUES(13,'MIR',1.84699993133544921e+01,'2026-05-11',10,'市场将MIR定义为传统辐射检测与测量的''商业服务公司''（见新闻9：''both business services companies''）','管理层明确点名''核电需求引领的大幅订单增长''，叠加多家机构投资者在Q3集中大幅加仓，市场对其核能基础设施受益者身份的认知正在加速重构。','1. 订单增速在后续季度出现环比下滑，或管理层下调FY2026收入/EBITDA指引；2. 核电项目宏观端出现监管收紧或主要客户推迟资本开支的可验证公告','公司宣布与SMR/先进反应堆开发商（如X-energy等）签署大额长期供货合同，或FY2026中期业绩显示EPS同比实现显著增长（突破$0.10的同比持平瓶颈），触发分析师集体上调目标价',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-1.01245208522162055e+01,NULL,NULL,NULL,'neutral','AI电力','行业重分类','SMR 故事在 2024-2025 可能已被 OKLO、SMR、NNE 等纯 pure play 透支一轮，市场对"SMR 配套供应商"的边际兴趣有可能已下降——Mirion 作为辐射监测设备商，单 SMR 合同的 dollar content 通常有限，即便签下 X-energy/TerraPower 也未必能 move the needle。Mirion 历史上有医疗辐射监测业务拖累整体增速的问题，FY2026 EPS 超预期有可能需要依赖非经常性项目（汇兑/税率）勉强达标——市场对其 earnings quality 存在 skepticism。SMR 商业化时间线持续右移（NRC 审批 + 燃料供应瓶颈），订单到收入确认通常有较长延迟。','医疗辐射业务拖累 - 监测 Medical segment 季度 organic growth 是否<3%; SMR 商业化时间线再延期 - 监测 NRC SMR design certification 进度（X-energy/NuScale/Holtec）; FX 逆风 - 监测 EUR/USD 是否跌破 1.05 对 Mirion 欧洲业务收入折算的影响','tentative',NULL,NULL,'2026-05-11','2026-05-18',1.84699993133544921e+01,18.08,'late_fill',275.7,63,'离/坎','体克用',70,'2020-08-20',NULL,NULL,NULL,NULL,NULL,NULL,10,64115214.57);
INSERT INTO "scanner_picks" VALUES(16,'HCC',8.71800003051757812e+01,'2026-05-11',9,'市场将HCC定义为一家受美国煤炭产量/消费量下滑拖累、面临多重行业挑战、值得回避的传统煤炭股','Q1 2026净利润从上年同期亏损820万美元骤升至7230万美元（EPS +1.37美元），超越分析师预期；核心增量来自Blue Creek扩产项目——该项目已提前整整8个月投产，属结构性产能跃升而非周期性波动','1. 若后续季度EPS重新回落至盈亏线附近，说明Q1利润为一次性价格脉冲而非Blue Creek产能持续贡献；2. 若分析师维持或下调评级且共识目标价不上修，说明市场已充分定价当前盈利改善','Q2 2026财报确认Blue Creek满负荷运转后EPS环比持续增长，触发多家持Hold评级的机构同步上调至Buy并提高目标价',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,8.4423039511214668e+00,NULL,NULL,NULL,'neutral','分析师重定价',NULL,'冶金煤可能是结构性衰退资产——欧洲 CBAM、中国钢铁产能压减、印度自给率提升三重因素叠加下，海运 met coal 需求有可能在未来数年内见顶。Blue Creek 满产即便兑现 EPS，市场给 met coal 公司的估值 multiple 历史上长期被锁在低位区间，"Hold→Buy"升级在周期股里有时与情绪/盈利顶部重合而非鸣枪起点。可比同业（AMCI、Warrior）持续低估值反映的未必是 mispricing，而可能是市场对终端需求 terminal value 的折价定价——这是煤炭行业结构性的估值锚。','海运冶金煤价格 - 监测 Platts Premium Low Vol HCC FOB Australia 是否跌破 $180/ton; 中国粗钢产量压减 - 监测 NBS 月度生铁/粗钢产量 YoY; 欧洲 CBAM 二阶段执行 - 监测 2026 H2 欧盟 CBAM 实施细则对冶金煤进口的间接影响','tentative',NULL,NULL,'2026-05-11','2026-05-18',8.71800003051757812e+01,85.67,'late_fill',275.7,46,'坤/离','体生用',67,'2017-04-13',NULL,NULL,NULL,NULL,NULL,NULL,6,87168936.005);
INSERT INTO "scanner_picks" VALUES(17,'FSS',1.17379997253417968e+02,'2026-05-11',9,'市场将FSS定义为一家分散经营的多行业综合企业（conglomerate），归类于汽车/工业板块，估值中性、分析师覆盖有限。','FSS Q1 2026实现净销售额同比增长35%、营业利润改善52%，每股收益$1.18大幅超越一致预期$0.89（超出约33%），且较去年同期$0.76增长55%；管理层随即上调全年业绩指引并提高EBITDA利润率目标，显示盈利能力系统性跃升而非一次性。','1. Q2 2026营收增速回落至个位数或低于管理层全年指引区间，表明New Way并购贡献为一次性而非持续驱动；2. 订单积压（backlog）环比下降，或Safety and Security Systems Group EBITDA利润率未能实现上调后目标。','机构分析师基于连续两个季度超预期+上调指引将评级从''Moderate Buy''集体升至''Strong Buy''并大幅上调目标价，触发动量资金追入重新定价。',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-1.01294936683108627e+01,NULL,NULL,NULL,'neutral','分析师重定价','公用事业现代化','Federal Signal 已经在 2024-2025 的市政基建主题中完成过一轮 rerate，"Moderate Buy → Strong Buy"的边际买盘空间可能相对有限——卖方评级集体上调历史上更常出现在 cycle 后期而非起点。Environmental Solutions 板块（街道清扫车/吸污车）周期性较强，依赖城市政府预算，联邦 ARPA 资金耗尽后市政 capex 有可能回落。FSS 的可比标的（Terex、Oshkosh）已经在 demand normalization 中下修指引，FSS 未必能独善其身——同板块 multiple compression 通常具有传染性。','市政 capex 回落 - 监测 Census 季度 State & Local Government Construction Spending YoY; ARPA/IIJA 资金落地放缓 - 监测 Treasury ARPA 季度 outlay 报告; 钢材/液压件成本反弹 - 监测 HRC 钢价突破 $900/ton 对 gross margin 的压制','tentative',NULL,NULL,'2026-05-11','2026-05-18',1.17379997253417968e+02,112.52,'late_fill',275.7,25,'离/坎','用克体',43,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,7,52646554.18);
INSERT INTO "scanner_picks" VALUES(18,'SOUN',8.44999980926513671e+00,'2026-05-11',9,'市场将SOUN定义为专注汽车和餐饮垂直领域的小众语音AI公司，股价已较高点大幅回落','公司发布OASYS平台，将自身定位从''语音AI''升级为''AI构建AI''的自学习代理AI平台，同时Q1营收创纪录达$44.2M（同比+52%），叙事框架正在发生系统性转变。此外与Richtech Robotics合作将语音代理AI嵌入机器人硬件，开辟新垂直市场。','1. 后续季度营收增速跌破30%或OASYS平台未能产生可披露的商业合同；2. Richtech Robotics合作从''非约束性意向书''阶段停滞不前，无法转化为正式协议','OASYS平台签下首个可披露的大型企业客户合同，或机器人+语音AI组合方案在餐饮/零售场景大规模部署并公布具体营收贡献',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-1.60946708565135452e+01,NULL,NULL,NULL,'neutral','AI软件',NULL,'SoundHound 在 conversational AI 赛道可能面对 OpenAI Realtime API、Google Gemini Live、ElevenLabs 的全面挤压，OASYS 平台的"差异化"在 LLM 时代有可能是 nice-to-have 而非 must-have——餐饮/汽车客户最终有可能迁移到通用 LLM 厂商的原生集成方案。公司当前估值显得远超多数软件可比标的，但 GAAP 亏损扩大、SBC 占营收比例偏高，单一客户合同披露未必能持续撑住估值。历史 pattern 上，SOUN 的"大客户签约"公告（与现代/奔驰/Olo 等）后倾向于出现显著回吐——市场对其 customer concentration 与 contract durability 存在反复怀疑。','OpenAI/Google 原生语音 API 蚕食 - 监测 OpenAI Realtime API GA 后定价和企业客户案例; SBC 占比与稀释 - 监测季度 diluted share count YoY 是否>20% 稀释; 现金消耗速度 - 监测季度 cash burn 与现金余额比值是否<6 个季度','tentative',NULL,NULL,'2026-05-11','2026-05-18',8.44999980926513671e+00,8.14,'late_fill',275.7,40,'艮/兑','体生用',57,'2022-04-28',NULL,NULL,NULL,NULL,NULL,NULL,8,197807564.13);
INSERT INTO "scanner_picks" VALUES(19,'VSEC',1.91210006713867187e+02,'2026-05-11',9,'市场仍将VSE Corporation定义为建筑/国防服务公司（部分数据源将其错误归类为''construction company''），低估其向纯航空售后市场分销与维修平台转型的战略价值','VSE已以约20.25亿美元完成对Precision Aviation Group（PAG）的收购，整合后形成横跨8国、拥有61个站点（48个维修设施）的规模化独立航空售后市场平台；同期Q1 2026营收同比增长26.8%，GAAP净利润同比增长108%，Adjusted EBITDA同比增长37.4%，增长具有连续性（Q4 2025营收同比+32%，净利润同比+114%）。','1. PAG整合出现成本超支或收入协同低于预期，导致后续季度Adjusted EBITDA增速明显回落；2. 分析师群体下调评级或目标价，股价进一步跌破52周低点$109.67。','机构投资者在5月20日B. Riley年度投资者大会后集体将VSEC重新定价为纯航空售后市场平台（而非建筑/国防标的），触发分类重构和估值体系切换。',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-1.02452857637282601e+01,NULL,NULL,NULL,'confirmed','行业重分类','分析师重定价','VSE 已经卖掉 Fleet 业务向"纯航空售后市场"转型的故事讲了两年，5 月 B. Riley 大会即便重新分类，可比标的（HEI、TDG、AAR）当前估值已处于 historical 高位，VSEC 即便完成切换，上行空间有可能小于下行风险。航空售后市场严重依赖窄体机机龄结构和 RPK 增长，波音/空客新机交付若重新加速，有可能拉低存量机队 aftermarket 需求。B. Riley sponsorship 的小盘股历史上出现过多次 conference 后回调 pattern（与 B. Riley 自身投行业务问题相关的小盘股流动性事件），这是市场对其 catalyst quality 结构性的 skepticism。','航空售后市场需求拐点 - 监测 Boeing/Airbus 月度交付量是否重回 2018 峰值水平; HEI/TDG 估值压缩 - 监测可比标的 forward EV/EBITDA 是否跌破 25x; B. Riley sponsorship 风险 - 监测 B. Riley Financial（RILY）自身股价/信用利差变化对其覆盖的小盘股流动性影响','tentative',NULL,NULL,'2026-05-11','2026-05-18',1.91210006713867187e+02,166.74,'late_fill',275.7,40,'艮/兑','体生用',37,'1982-10-22',NULL,NULL,NULL,NULL,NULL,NULL,8,1.1344120394749999e+08);
INSERT INTO "scanner_picks" VALUES(20,'LIF',4.3279998779296875e+01,'2026-05-11',9,'市场将Life360定义为中型市值工业/安防服务类股，与传统硬件安全公司（如ADT、REZI）归为同类','尽管股价年初至今下跌35%，Life360 FY26指引收入$640–$680M（同比增长31–39%），调整后EBITDA利润率目标20.3%，多家机构同步上调评级至买入，估值压缩与基本面背离显著扩大。','1. FY26实际收入低于指引下限$640M，或MAU增速跌破20%；2. 调整后EBITDA利润率未能如期向20.3%扩张，说明盈利改善为一次性。','FY26 Q1财报确认收入增速及EBITDA利润率双双达标，触发市场从''工业类''旧框架向''高增长SaaS+硬件平台''重新定价。',NULL,NULL,'filled_late',NULL,NULL,285.33,'GRID',1.99800003051757812e+02,NULL,NULL,NULL,NULL,-1.82531682789227733e+00,NULL,NULL,NULL,'confirmed','行业重分类','AI软件','"工业旧框架 → SaaS+硬件平台新框架"的重分类故事在小盘股里历史成功率偏低——Bel Fuse、Vicor、Powell Industries 都曾尝试过类似 narrative shift，最终估值多数回到工业 P/E 区间。市场对"高增长 SaaS+硬件"组合的估值倍数自 2022 后已结构性压缩（Samsara、PTC 等可比标的 multiple 已显著回落），即便重分类成功也未必带来 multiple expansion。LIF 流动性偏低、机构持仓集中，一旦初期买盘耗尽有可能出现 air pocket 式回调——小盘股 narrative trade 的 tail risk 历史上就在流动性结构上。','SaaS ARR 占比未达临界 - 监测季度 recurring revenue % 是否突破 40%; 工业可比标的 multiple 压缩 - 监测 PTC/AZPN/Samsara forward EV/Sales 是否继续下降; 小盘股流动性枯竭 - 监测日均成交额是否跌破 $5M 触发指数基金减持','tentative',NULL,NULL,'2026-05-11','2026-05-18',4.3279998779296875e+01,39.135217,'late_fill',275.7,66,'离/坎','体克用',31,'2024-06-06',NULL,NULL,NULL,NULL,NULL,NULL,9,55435404.72);
INSERT INTO "scanner_picks" VALUES(21,'GNTX',2.26800003051757812e+01,'2026-05-18',10,'市场将 Gentex 定义为一家成熟的汽车自动防眩镜市场领导者，增长天花板已现、高度依赖整车生产周期的传统零配件供应商。','VOXX 收购拉动 Q1 营收同比增长 17%，毛利率扩张 200bps，管理层同步上调 2026 年营收指引并将 2027 年营收指引提升至 28–29 亿美元；公司正向生物识别与智能家居安全等新品类延伸，叙事框架从''成熟零配件''向''多品类技术平台''切换，分析师开始使用''step function change''与''re-rating''措辞。','1. VOXX 收入贡献剥离后有机增速转负，说明核心镜类业务加速萎缩；2. 管理层在后续季报中下调 2027 年营收或 EPS 指引，显示当前提升系 VOXX 并表而非内生增长驱动。','若 Q2/Q3 业绩继续验证 VOXX 协同效应（有机收入保持正增长、毛利率继续扩张），且管理层在财报电话会上明确给出生物识别或智能家居新品类的量产时间表，可能触发分析师覆盖升级与估值框架重构。',NULL,NULL,'filled',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,NULL,NULL,NULL,NULL,9.61199416156218156e+00,NULL,NULL,NULL,'neutral','分析师重定价','行业重分类','市场可能永远不买账，原因在于 Gentex 历史上以高护城河单一产品（自动防眩镜）享有溢价，但该溢价的核心是''垄断性利基''而非''成长性平台''——一旦公司向生物识别与智能家居扩张，市场可能将其重新归类为''多元化但护城河模糊的中型科技零配件公司''，反而导致估值压缩而非扩张；此外，VOXX 历史上属于消费电子分销商而非高毛利技术公司，收购整合所带来的叙事改善可能掩盖利润率结构的实质性摊薄；同时，多家机构（North Point、Birch Hill、Alpha Omega）在近期集中减持，暗示熟悉公司基本面的长期持有人可能对新叙事持保留态度，认为当前估值已 potentially price in 部分乐观预期，向上空间有限。','VOXX 整合协同兑现风险 - 监测每季有机收入增速（剔除 VOXX 并表影响）及 VOXX 毛利率贡献趋势；关税政策与供应链成本压力 - 监测美国汽车关税变动及 GNTX 管理层季报中关税相关成本指引更新；中国市场持续承压 - 监测中国轻型车产销量月度数据及 GNTX 中国区收入占比变化','tentative',NULL,NULL,'2026-05-18','2026-05-19',2.26800003051757812e+01,22.56,'auto_filled',273.0,66,'乾/离','体克用',74,'1981-12-22',NULL,NULL,NULL,NULL,NULL,NULL,9,5.25881301200000047e+07);
INSERT INTO "scanner_picks" VALUES(22,'GWRE',1.37089996337890625e+02,'2026-05-18',10,'市场将GWRE定义为传统P&C保险核心系统提供商，正在进行云迁移转型，增长潜力受制于保险行业缓慢的技术替换周期','Guidewire推出了ProNavigator AI助手，嵌入InsuranceSuite和InsuranceNow核心应用，显示其产品叙事可能正从''云迁移故事''转向''AI原生平台''。与此同时，RPO同比增长63%至35亿美元，客户平均新合同期限超过六年，暗示平台粘性可能正在结构性提升。','ProNavigator发布后连续两个季度内无法提供可量化的客户采用指标或AI相关收入贡献数据；RPO同比增速从63%出现明显回落或出现头部客户不续约信号','下一季度财报中ProNavigator的客户采用数据或AI附加产品ARR占比首次披露，若同步伴随全年ARR指引上调，可能触发市场对其估值框架的重新定价',NULL,NULL,'expired',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','AI软件','行业重分类; 分析师重定价','市场对GWRE的低估框架可能部分合理：保险核心系统替换历史上周期极长，ProNavigator的AI功能可能被视为现有产品的功能更新而非结构性定价权来源，竞争对手（如Duck Creek、Majesco）可能推出类似AI嵌入方案从而压缩差异化溢价空间。Brown Advisory等机构已明确认识到其''竞争定位被低估''，这暗示聪明钱已开始入场，潜在的''认知差''可能已在收窄而非扩大。此外，RPO的高增长和长期合同结构可能已被部分乐观的分析师充分反映在估值模型中，历史上类似SaaS转型故事在RPO高位后往往出现增速均值回归，导致市场预期落差。','AI功能商品化风险 - 监测Duck Creek/Majesco/其他P&C软件竞争对手季报中AI产品公告及客户win/loss披露；客户集中度风险 - 监测季报中前五大客户ARR占比变化及是否出现大客户延迟续约通知；云迁移节奏风险 - 监测每季净新增全云ARR增速是否连续低于此前指引区间','tentative',NULL,NULL,'2026-05-18',NULL,1.37089996337890625e+02,NULL,'auto_expired',NULL,28,'乾/离','用克体',75,'2012-01-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(23,'OLLI',8.13700027465820312e+01,'2026-05-18',10,'市场将OLLI定义为依赖过剩库存与破产清算机会的被动型closeout折扣零售商，业绩随供应链扰动周期性波动','OLLI''s Army忠诚会员计划增速显著，同时管理层披露创纪录的门店扩张速度并设定明确的长期门店数量目标，暗示公司可能正从机会主义折扣商向具有规模化重复客群资产的成长型零售平台转型。消费者在关税与经济压力下主动向深折扣渠道迁移，为这一转型提供结构性外部支撑。','1. 门店开业节奏实质性低于75家年度目标，或管理层在财报中下调指引；2. OLLI''s Army会员增速连续两个季度降至个位数，客单价未出现对应提升','2026财年门店净开业数可验证地达到75家目标，同时OLLI''s Army会员数增速在季报中连续披露高于20%，触发市场将其估值框架从周期性折扣商切换至具备可量化留存资产的成长零售平台',NULL,NULL,'expired',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','分析师重定价','行业重分类','市场可能永远不接受重定价的核心理由在于：closeout模式本身的护城河历史上高度依赖外部供应端扰动（破产潮、供应链过剩），一旦宏观信用环境改善、破产率回归正常，OLLI的进货优势可能结构性收窄，而届时规模扩张所积累的固定成本反而构成杠杆负担。此外，OLLI''s Army的会员增长目前仅有原文百分比数据，缺乏ARPU、复购频次等深层指标验证，市场可能持续对loyalty变现能力保持怀疑，认为其与Dollar General、Five Below的差异化尚未达到系统性重定价所需的信服度。机构投资者层面，原文显示部分大型机构同期大幅减持，这可能暗示sophisticated资金认为当前估值已较充分反映成长预期，进一步上行空间有限。','破产与清算供应端收缩 - 监测季度破产申请数据及零售行业库存过剩指标，若供应稀缺化则进货成本优势可能消退；快速扩张执行风险 - 监测单店销售额（SSS）与新店爬坡数据，若新开门店拖累整体坪效则扩张逻辑崩塌；消费者信心反弹导致交易上移 - 监测密歇根消费者信心指数及高端零售同店销售，若消费者重回正常价位段则trade-down尾风消散','tentative',NULL,NULL,'2026-05-18',NULL,8.13700027465820312e+01,NULL,'auto_expired',NULL,66,'坎/坤','体克用',35,'2015-07-16',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(24,'ASTE',47.5,'2026-05-18',9,'市场将ASTE定价为传统基础设施设备制造商，依赖周期性需求、利润率薄、盈利能力受大宗成本波动压制。','Q1 2026订单积压（Backlog）同比大幅增长36.4%至5.492亿美元，显示前向需求显著改善；与此同时，股价突破200日均线，新鲜分析师覆盖开始跟进，市场认知框架可能正在切换。','Q2 2026订单积压增速回落至个位数或绝对值下降；或Investor Day上管理层未能就GAAP与Adjusted EPS之间的巨大差距（$0.06 vs $0.54）提供可验证的收敛计划。','2026年5月13日Investor Day虚拟路演，若管理层提供明确的利润率改善路径（将Adjusted EPS向GAAP EPS收敛的时间表）以及订单积压转化为收入的节奏指引，可能触发市场对盈利能力的重新定价。',5.02299995422363281e+01,5.74736745733963813e-02,'closed_watching',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,'thesis_invalidated','Investor Day 5/13已召开但股价不涨反跌；管理层未能提供GAAP/Adjusted EPS收敛时间表；市场认知框架未切换，thesis失效条件触发',7.3754998779296875e+02,1.8755999755859375e+02,4.7368421052631584e+00,'[{"date": "2026-06-07", "price": 50.22999954223633}, {"date": "2026-06-08", "price": 51.36000061035156}, {"date": "2026-06-10", "price": 52.09000015258789}]',5.20900001525878906e+01,NULL,'neutral','分析师重定价','行业重分类','市场对ASTE的低估值框架可能结构性合理：当季GAAP EPS仅$0.06而Adjusted EPS为$0.54，两者差距高达约9倍，历史上大量依赖调整项来呈现利润的工业公司在真实现金盈利能力上往往存在持续折价风险。订单积压增长36.4%部分由收购驱动（"acquisition-driven sales gains"），市场可能担忧这属于一次性并表效应而非有机需求加速。此外，GF Value已将股价标记为"Overvalued"，若以历史周期估值模型看，Backlog-to-Earnings转化率若持续低于预期，当前股价涨幅或已将乐观情景定价完毕，后续重定价空间可能有限。管理层曾在本季度显著低于市场一致预期（$0.54 vs $0.88），其对利润率改善的执行能力尚未获市场信任背书。','利润率压缩持续恶化 - 监测Q2 2026 Adjusted EBITDA Margin是否跌破当前水平（Q1为约7.6%）；收购整合失败 - 监测后续季度Backlog转化率（Book-to-Bill Ratio）是否出现实质性下滑；制造业PMI反转 - 监测ISM制造业PMI是否跌回收缩区间（低于50）并连续两月确认','failure','catalyst','催化剂Investor Day如期发生但市场无正面响应，EPS差距未得到足够解释，重定价未发生','2026-05-18','2026-05-19',47.5,48.78,'auto_filled',2.71089996337890625e+02,34,'艮/乾','体生用',65,'1986-06-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(25,'CXT',3.83400001525878906e+01,'2026-05-18',9,'市场将CXT定义为以货币防伪/工业技术为核心的传统工业科技公司（"premier industrial technology company"）','公司完成收购Antares Vision，将定位从货币鉴别切换至"全球认证与溯源技术领导者"，同时将业务版图扩展至约30亿美元规模的生命科学与食品饮料领域；Q1 2026有机销售增长6%，EPS超预期且维持全年指引，显示核心业务扩张期间基本面依然稳健。','1. Antares Vision收购后出现商誉减值或整合费用超预期，导致管理层下调全年EPS指引（低于$4.10）；2. 有机销售增速在后续两个季度明显回落（跌至低个位数），说明核心认证业务扩张动能可能不持续。','2026年Q2财报（约8月）首次披露Antares Vision收入合并贡献与协同效应量化数据，若生命科学/食品饮料溯源业务营收占比明显提升，可能触发分析师将估值框架从工业制造切换至技术平台，进而引发评级上调。',NULL,NULL,'expired',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','行业重分类','分析师重定价','市场可能长期维持工业科技估值框架，原因在于CXT核心收入历史上可能高度依赖各国央行货币更新周期，这是一个受政策驱动、增长天花板相对明确的市场，平台化叙事并不能从结构上改变这一底层约束。Antares Vision进入生命科学/食品饮料检测领域，面对的是已有成熟玩家的竞争格局，CXT在这一赛道的客户关系与渠道积累可能相当薄弱，整合风险可能被当前新闻叙事所掩盖。历史上，工业公司宣称向技术平台转型的案例中，市场给予重定价的时间窗口通常需要多个季度持续兑现，仅凭一次收购完成公告可能不足以驱动持续的估值扩张。此外，当前"Moderate Buy"共识中有3家持有评级，分析师对转型逻辑的认可度尚未形成合力，保守评级可能反映市场对整合执行能力的结构性疑虑。','Antares Vision整合失败风险 - 监测Q2/Q3财报中整合费用、商誉减值迹象及生命科学业务毛利率是否低于核心业务；核心货币认证业务需求周期性下滑 - 监测管理层Q2电话会议中央行订单能见度表述及地理收入集中度变化；流动性与分析师覆盖不足风险 - 监测覆盖该股分析师数量是否从当前7家扩展，以及机构持仓换手率是否出现异常集中抛售','tentative',NULL,NULL,'2026-05-18',NULL,3.83400001525878906e+01,NULL,'auto_expired',NULL,75,'离/巽','用生体',72,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(26,'APPF',1.57910003662109375e+02,'2026-05-18',9,'市场将 AppFolio 定义为服务中小型物业管理公司的传统按席位计费 SaaS，受制于房地产周期与有限地址市场（TAM），估值框架偏向保守的成长型 SaaS 倍数。','Q1 2026 业绩超预期并上调全年营收指引，同期分析师确认其定价模型与出租单元数量挂钩而非按席位收费，使其在 SaaSpocalypse 叙事中结构性隔离；股价同步突破50日均线，技术面确认基本面改变。','全年营收指引在 Q2 财报中被下调或维持不变（而非上调）；营收增速连续两季跌破15%，表明单元扩张动能趋缓而非加速。','Q2 2026 财报若再次确认营收增速维持20%以上且全年指引再度上调，将可验证 beat-and-raise 不是一次性事件，触发分析师从「成长型 SaaS」框架向「Rule of 40 平台化公司」框架切换的集体重定价。',NULL,NULL,'expired',NULL,NULL,2.75970001220703125e+02,'GRID',1.89220001220703125e+02,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','分析师重定价','AI软件','市场可能永远不会完成重定价，原因在于：其一，当前分析师覆盖虽有10家且共识为Buy，但38.8%的隐含上行空间可能已充分反映于当前估值——若股价在近期快速修复后已 approaching 分析师目标价，则 repricing thesis 的时间窗口可能已收窄；其二，按单元数量计费的模式虽区别于按席位计费，但其 TAM 上限与美国出租单元总量高度绑定，历史上此类垂直 SaaS 最终均面临单元增速天花板，市场可能提前 price in 成熟期减速；其三，Tour24 等第三方集成生态虽扩大了可寻址场景，但 AppFolio Stack Marketplace 模式历史上在物业管理垂直赛道内曾被 Yardi、RealPage 等竞争对手以更大生态规模复制，市场或将其视为防御性竞争护城河而非进攻性增长引擎，从而给予更低溢价；其四，Q1 beat-and-raise 发生于宏观背景仍不确定的环境下，此类季度超预期在 SaaS 板块历史上多次出现后随即因宏观收紧而逆转，市场可能倾向于等待至少两个季度的连续验证才愿意承认结构性改变。','出租单元净增速放缓 - 监测 AppFolio 季报中「units under management」同比增速是否跌破8%；SaaS 板块系统性估值压缩 - 监测 IGV ETF 较高点回撤幅度，若超过20%则 APPF 估值锚将随板块漂移；竞争对手定价战 - 监测 Yardi/RealPage 季报或新闻中是否出现针对中小物业管理市场的降价/捆绑销售公告','tentative',NULL,NULL,'2026-05-18',NULL,1.57910003662109375e+02,NULL,'auto_expired',NULL,37,'艮/乾','体生用',73,'2015-06-26',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(27,'MP',6.44599990844726562e+01,'2026-05-25',11,'市场将 MP Materials 定义为周期性稀土矿业公司，估值随大宗商品价格波动','MP Materials 正从单一矿业公司转型为涵盖采矿、精炼到磁铁制造的全链条战略工业平台，获得美国政府结构性价格底线协议支撑，且 Q4 2025 已出现正 EBITDA 拐点信号。','Magnetics Segment 连续两季度收入低于管理层指引且毛利率为负；或美国政府价格底线协议条款被修改或取消，下行保护结构性消失','即将发布的 Q1 2026 财报若首次披露 Magnetics Segment 收入并高于市场预期，可能触发分析师将估值框架从大宗商品矿商切换至工业制造商，引发目标价体系性上调',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','行业重分类','分析师重定价','市场对矿业公司维持折价框架可能在结构上是合理的：历史上稀土及战略矿产领域的''垂直整合''叙事曾多次被寄予厚望，但制造端爬坡缓慢的问题可能再次出现；Lynas 在同期分析师比较中被描述为具备''stronger growth, rising estimates and long-term supply deals''，资金可能倾向于这类更成熟的替代标的；当前股价月涨幅已较显著，政府支持叙事可能已部分反映在估值中，额外催化剂的增量效应或较为有限；此外停止对华销售虽被叙述为主动转型，但也可能揭示潜在客户集中度风险——若国内替代需求爬坡慢于管理层预期，转型叙事的可信度可能受到持续质疑','美国政府价格底线协议续签风险 - 监测 DoD/DoE 合同公告及协议条款变化信号；中美稀土贸易关系逆转 - 监测中美双边谈判进展及中国稀土出口管制松绑公告；Magnetics Segment 制造爬坡失败 - 监测连续两季度 Magnetics 收入占比及毛利率是否持续改善','tentative',NULL,NULL,'2026-05-25',NULL,6.44599990844726562e+01,NULL,'auto_pending',NULL,46,'离/震','体生用',62,'2020-06-22',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(28,'APPF',1.64919998168945312e+02,'2026-05-25',10,'市场将 AppFolio 定义为一家传统按席位计费的物业管理 SaaS 公司，受整体软件板块估值压缩和 ''SaaSpocalypse'' 叙事拖累。','Q1 2026 业绩超预期并上调全年收入指引，同时分析师明确指出其定价模型与租赁单元扩张挂钩而非按席位收费，结构上隔离了 per-seat SaaS 风险；收入增速保持 20%+ 同时利润率持续扩张，已进入 Rule of 40 阵营。','①管理层在后续季度下调全年收入指引，或实际收入增速低于当前指引区间；②每管理单元平均收入（ARPU）连续两季度同比下滑，显示 value-added services 渗透率遭遇天花板。','Q2 2026 财报（可验证事件）若再次确认收入增速维持 20%+ 且利润率继续扩张，将可能触发市场将 APPF 从 ''SaaS 软件折价篮子'' 重新定价至 ''Rule of 40 premium 平台'' 框架，因为当前分析师共识仍存在约 38.77% 的目标价上修空间。',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','分析师重定价','AI软件; 行业重分类','市场对 APPF 的乐观情绪可能已在当前股价中得到较充分体现——10 位分析师中 9 位评级买入或强烈买入，这种高度一致的看涨共识历史上往往 suggests 边际买家稀缺，股价可能难以在短期内大幅超越分析师目标价。此外，APPF 的增长逻辑深度绑定租赁单元数量扩张，若宏观环境导致多户型公寓新建放缓，单元扩张驱动的收入模式可能面临结构性压力，而该风险尚未在当前叙事中被充分定价。更值得警惕的是，Tour24 等第三方集成虽然丰富了生态，但也 potentially 表明核心 AppFolio 平台在某些功能上存在补充需求，竞争对手若直接内嵌类似功能可能削弱平台粘性。历史上高速增长的垂直 SaaS 公司在渗透率接近目标市场饱和点后，往往经历多个季度的增速台阶式下降，而市场往往在第一个 miss 出现之后才重新定价。','多户型公寓新开工量持续下滑 - 监测美国 Census Bureau 每月多户型住宅开工数据连续低于前值；Value-added services 渗透率增长停滞 - 监测每季度财报中 ARPU 趋势及管理层对附加服务 attach rate 的描述语言变化；软件板块整体估值收缩加剧 - 监测 IGV (iShares Expanded Tech-Software ETF) 相对 S&P 500 的表现及 10 年期美债收益率走势','tentative',NULL,NULL,'2026-05-25',NULL,1.64919998168945312e+02,NULL,'auto_pending',NULL,68,'艮/坤','比和',34,'2015-06-26',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(29,'KTB',6.9910003662109375e+01,'2026-05-25',10,'市场将KTB定义为以Wrangler和Lee为核心的传统工装/休闲服饰公司，Lee持续下滑拖累整体增长预期','公司宣布计划剥离Lee品牌并启动7.5亿美元股票回购，同时Helly Hansen交出优于预期的营收与盈利表现，标志着KTB正从Lee拖累的双品牌模式向Wrangler+Helly Hansen增长平台转型。全年指引同步上调。','1. Helly Hansen在Q2 2026季报中营收或盈利低于预期，表明Q1超预期为一次性；2. Lee剥离交易流产、延期或成交价显著低于市场预期，暗示资产质量差于管理层所描述','Lee品牌剥离交易正式完成并披露成交价格，若定价合理或高于预期账面价值，市场可能被迫将KTB重新定价为纯Wrangler+Helly Hansen增长平台，触发分析师覆盖框架切换与目标价上修',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','分析师重定价','行业重分类','市场可能长期不买账，因为服饰行业''剥离拖累品牌、押注新收购品牌''的重组叙事历史上成功率参差不齐——Helly Hansen的户外市场structurally竞争激烈，North Face、Arc''teryx等成熟玩家已深度占据高端心智，KTB作为后发整合者可能面临持续的品牌溢价挑战。7.5亿美元回购规模相对市值较大，市场skepticism在于：这potentially反映管理层缺乏有机再投资机会，而非纯粹的股东价值信心信号。此外，EPS missed外部一致预期（$1.06 vs $1.17），说明公司当前实际盈利能力与市场预期之间appears存在结构性落差，即便全年指引上调也可能被解读为管理层调低基准后的相对容易达成。','Strait of Hormuz/亚洲供应链中断 - 监测KTB季报中亚洲采购占比披露及毛利率环比变化；Lee剥离实际成交估值 - 监测交易公告中EV/Revenue或P/Book倍数是否低于同类可比交易；Helly Hansen增长持续性 - 监测Q2 2026 Helly Hansen分部营收增速是否低于Q1，以及是否存在一次性季节性因素贡献','tentative',NULL,NULL,'2026-05-25',NULL,6.9910003662109375e+01,NULL,'auto_pending',NULL,81,'坤/乾','用生体',68,'2019-05-28',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(30,'GNTX',2.38500003814697265e+01,'2026-05-25',10,'市场将 GNTX 定义为依赖全球轻型车产量周期的成熟汽车自动调光后视镜制造商，估值框架以传统汽车零部件供应商为锚。','VOXX 收购带动 Q1 2026 营收同比跳升 17%，毛利率扩张 200bps，2027 年营收指引上调至 $2.8–$2.9B；同时管理层将公司定位从''后视镜供应商''向生物识别与智能家居安全延伸，有机增长在全球轻型车产量下滑背景下依然为正，分析师开始使用''re-rating''与''step function change''等语言。','① 连续两个季度毛利率回落至 VOXX 收购前水平，说明扩张依赖一次性并表效应而非结构性改善；② 中国市场收入持续双位数下滑且管理层在季报中下调 2027 指引，表明地域性逆风强度超过有机增长对冲能力。','Q2 2026 财报若在 VOXX 收入剥离/单独披露后仍显示有机毛利率维持扩张趋势，且管理层首次提供生物识别/智能家居业务的独立营收贡献数字，将为市场提供可验证的''不再是纯汽车零部件''再定价锚点。',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','分析师重定价','行业重分类','汽车自动调光玻璃市场可能面临结构性渗透率天花板，历史上类似的汽车零部件供应商在向相邻科技市场多元化扩张时，往往难以获得市场给予科技企业的估值倍数——市场可能持续以汽车周期折现率为锚，而非将生物识别与智能家居业务贡献视为可信的长期增长驱动。VOXX 收购带来的规模效应可能掩盖后视镜核心业务的有机量价双降，若 VOXX 收入贡献在未来季报中无法被清晰剥离，市场对''新故事''的信任度可能长期停留在观望状态。此外，北点资本等机构在 Q1 大规模减持的行为，historically 在成长故事再定价初期通常伴随聪明钱对执行风险的早期定价，暗示机构层面对管理层多元化执行能力可能存在持续分歧。','VOXX 整合执行风险 - 监测季报中 VOXX 与原有业务的分部毛利率是否单独披露，若始终合并披露则难以验证有机改善可持续性；中国市场收入侵蚀 - 监测 GNTX 季报中中国收入占比变化及管理层对中国客户集中度的表述；关税对供应链成本的传导 - 监测 Q2/Q3 2026 毛利率绝对值是否出现回落并伴随管理层上调成本指引','tentative',NULL,NULL,'2026-05-25',NULL,2.38500003814697265e+01,NULL,'auto_pending',NULL,65,'乾/兑','比和',34,'1981-12-22',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(31,'WTS',3.0244000244140625e+02,'2026-05-25',10,'市场将WTS定义为传统工业水处理公司，以稳健分红和周期性工业需求为估值锚点','Q1 2026创纪录业绩由数据中心需求驱动，管理层明确将AI基础设施需求列为核心增长引擎，而非仅靠定价和效率改善；此前分析师预判其无法超预期，实际EPS大幅超出共识。','管理层在Q2业绩会上将数据中心相关收入表述从''需求驱动''降级为''个别项目''或不再单独提及；或连续两个季度有机增长重回个位数且毛利率收缩','Q2 2026财报（约2026年8月）若管理层将数据中心收入单独披露或首次上调全年guidance并点名AI基础设施为驱动，可验证此thesis是否触发分析师重评级覆盖和机构重新建仓',NULL,NULL,'filled',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,6.27397366431108327e+00,NULL,NULL,NULL,'neutral','AI电力','分析师重定价','市场可能永远不会将WTS重新定价为AI基础设施受益股，原因在于：其水处理产品在数据中心供应链中属于被动配套而非核心壁垒，超大型云厂商采购决策中水冷方案可能被气冷或液冷替代方案逐步取代；历史上工业公司借助科技叙事获得短暂估值溢价后，一旦该客户垂直整合或更换供应商，溢价往往迅速消退；加之WTS体量与真正的AI基础设施纯玩家相比较小，机构资金配置AI主题时可能优先选择更具直接暴露度的标的，WTS的重定价窗口可能在叙事尚未扩散前即被下一轮宏观扰动打断','超大型数据中心资本开支周期回落 - 监测AWS/Azure/Google季度capex指引是否出现明显下调；水冷替代技术渗透提速 - 监测竞争对手（如Vertiv、Schneider Electric）液冷/气冷解决方案季报中数据中心份额增长；欧洲业务拖累整体增长 - 监测WTS欧洲分部有机增长率是否连续为负','tentative',NULL,NULL,'2026-05-25','2026-05-26',3.0244000244140625e+02,306.99,'auto_filled',290.510009765625,59,'震/巽','比和',41,'1986-08-21',NULL,NULL,NULL,NULL,NULL,NULL,9,8.6813579399999991e+07);
INSERT INTO "scanner_picks" VALUES(32,'SPXC',2.07800003051757812e+02,'2026-05-25',10,'市场用「工业/建筑周期股」框架定义SPXC，将其视为与施工景气度挂钩的传统制造企业','SPXC数据中心冷却业务正从边缘分部演变为核心增长引擎，Olympus Max产品已获多年期客户承诺及大额订单，数据中心营收被预测以年化约50%的速度增长，有望在数年内由当前小份额扩张至总营收的重要占比。Q1 2026财报同步验证整体盈利能力持续超预期。','①连续两个季度数据中心相关订单增速明显放缓，或Olympus Max关键客户退出多年期承诺；②非数据中心主业营收持续下滑且管理层下调全年指引，说明数据中心增长可能是掩盖基本面恶化的短期噪音','Q2或Q3 2026财报中管理层首次在分部披露中将数据中心冷却单独列示，且该分部收入同比增速可被独立核实，触发机构投资者将SPXC从建筑股重新归类至AI基础设施赛道',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','AI电力','分析师重定价; 行业重分类','市场可能长期维持「建筑股」旧框架，因为数据中心业务目前在总营收中占比仍相对有限，历史上单一新分部的高增速叙事在未超过总营收约三分之一之前往往难以驱动主流机构重分类。分析师共识目标已隐含可观上行空间，暗示AI冷却主题可能已被部分市场参与者定价，潜在重定价边际效应可能随时间收窄。此外，Vertiv等数据中心冷却专业玩家在技术深度与客户关系上历史上具备先发优势，市场可能对SPXC在该赛道能否维持高于行业平均的增速持结构性怀疑。最后，SPXC多元化的业务组合使其估值框架存在歧义，机构可能倾向于给予混合折价而非纯AI基础设施溢价。','超大规模云厂商AI资本支出预期回落 - 监测AWS/Azure/Google/Meta季报中数据中心基础设施capex指引，若任一主要客户下调支出规模则订单可见度受损；数据中心冷却赛道价格竞争加剧 - 监测Vertiv季报毛利率变化及其新产品发布节奏，若Vertiv压价抢单则SPXC定价权受威胁；SPXC传统暖通与建筑业务出现加速恶化 - 监测非数据中心分部季度有机营收增速，若连续两季转负则增长结构可疑','tentative',NULL,NULL,'2026-05-25',NULL,2.07800003051757812e+02,NULL,'auto_pending',NULL,43,'离/震','体生用',75,'1980-03-17',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "scanner_picks" VALUES(33,'ROCK',3.71800003051757812e+01,'2026-05-25',9,'市场将Gibraltar Industries定位为横跨住宅建材、农业技术与可再生能源的多元建筑制造商','公司正主动执行两步式可再生能源业务剥离战略，已将Renewables重分类为discontinued operations并以7000万美元现金出售eBOS业务；与此同时，董事会成员在二级市场大额增持，暗示内部人士认为核心业务存在重定价机会。','1. 第二步剥离长期无进展或以显著折价完成，说明Renewables资产变现能力弱于预期；2. 核心建筑产品业务连续两个季度EPS同比继续大幅下滑（Q1 2026已出现年同比约53%下降），说明剥离行动掩盖而非解锁了价值','可再生能源业务''两步剥离''第二步完成公告（即剩余Renewables资产出售），可验证时间点为管理层在Q1 2026业绩电话会或后续投资者会议中披露交割时间表',NULL,NULL,'expired',NULL,NULL,2.851199951171875e+02,'GRID',192.5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'neutral','行业重分类','分析师重定价','市场可能永远不会重定价ROCK，因为核心建筑产品业务的盈利能力appears to be structurally compressing独立于可再生能源剥离之外——Q4 2025和Q1 2026的EPS均较前年同期大幅下滑，suggests the Renewables drag may historically have obscured a pre-existing deterioration in the legacy building business rather than being its primary cause。大型机构投资者（Allspring减持逾90%、JPMorgan减持25%）的同步撤退potentially signals sophisticated money has already priced in the restructuring upside and sees limited incremental re-rating。此外，''两步剥离''叙事已见诸多条公开新闻，market skepticism could center on whether the thesis is already fully reflected in insider buying and conference appearances rather than being a hidden catalyst。历史上，以''聚焦核心''为由的连续剥离型重组，若核心业务本身增长动能不足，市场给予的估值倍数扩张往往低于预期。','核心建筑产品业务盈利能力持续承压 - 监测Q2/Q3 2026 EPS是否连续低于前年同期且miss分析师预期；第二步可再生能源资产剥离估值大幅折价 - 监测第二步出售公告中披露的交易对价（以第一步eBOS的$70M作为市场隐含参考基准）；大型机构加速清仓 - 监测下一期13F文件中Allspring剩余32,221股及JPMorgan 135,341股是否进一步减持至接近清零','tentative',NULL,NULL,'2026-05-25',NULL,3.71800003051757812e+01,NULL,'auto_pending',NULL,71,'艮/坤','比和',61,'1993-11-05',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
