INSERT INTO "signals" VALUES(3,'ACM','2026-05-06','news','Type One Energy, Tokamak Energy, and AECOM Form the UK Infinity Fusion Consortium to Accelerate Development of a Commercial Fusion Power Plant in the United Kingdom','LONDON--(BUSINESS WIRE)--Type One Energy, Tokamak Energy, and AECOM today announced the UK Infinity Fusion Consortium to pursue development of the first private-sector-led fusion power plant project in the United Kingdom. Together, the companies intend to develop a fusion project that is commercially credible, deployable using existing enabling technologies, and capable of attracting private capital — consistent with the long-term goals of the government''s recently announced UK Fusion Strategy.','Business Wire','2026-05-06T23:45:23','medium');
