INSERT INTO "signals" VALUES(19,'AGYS','2026-05-04','news','Agilysys to Report Fiscal 2026 Fourth Quarter Results May 18th and Host Conference Call and Webcast','ALPHARETTA, Ga.--(BUSINESS WIRE)--Agilysys, Inc. (AGYS), a leading global provider of hospitality software and services, announced today that it will release its fiscal 2026 fourth quarter results after the market closes on Monday, May 18, 2026 and host a conference call and webcast at 4:30 p.m. ET that day. Both the call and webcast are open to the public. All participants should register for the call using the participant registration URL: https://register-conf.media-server.com/register/BI090.','Business Wire','2026-05-06T23:45:28','medium');
