INSERT INTO "signals" VALUES(23,'ALG','2026-05-04','news','ALAMO GROUP ANNOUNCES FINANCIAL RESULTS FOR THE FIRST QUARTER 2026','SEGUIN, Texas, May 4, 2026 /PRNewswire/ -- Alamo Group Inc. (NYSE: ALG) today reported results for the first quarter 2026. Highlights: Net sales were $417.1 million, up 6.7% compared to the first quarter of 2025 Net income was $29.2 million and adjusted net income was $31.1 million Fully diluted EPS was $2.41 per share and adjusted fully diluted EPS was $2.56 per share Adjusted EBITDA of $59.3 million was 14.2% of net sales, up 1.8% compared to the first quarter of 2025 Net sales in the Industrial Equipment Division increased 6.5% compared to the first quarter of 2025 Net sales in the Vegetation Management Division increased 7.0% compared to the first quarter of 2025 Successfully closed the Petersen acquisition and commenced work on synergy realization Debt, net of cash, was $95.2 million ','PRNewsWire','2026-05-06T23:45:30','medium');
