INSERT INTO "signals" VALUES(5471,'UTL','2026-05-05','8k','UNITIL CORP  (UTL)  (CIK 0000755001) 8-K Item 1.01, 2.03, 9.01','Item 1.01 Entry into a Material Definitive Agreement. On April 30, 2026, Fitchburg Gas and Electric Light Company ( Fitchburg ), an electric and natural gas distribution utility subsidiary of Unitil Corporation (the Company or the Registrant ), entered into a Note Purchase Agreement with State Farm Life Insurance Company, State Farm Life and Accident Assurance Company and CoBank, ACB (the Note Purchase Agreement ) pursuant to which it issued and sold (i) $23,000,000 of 5.62% Senior Unsecured Notes, Series 2026A, due April 30, 2036 and (ii) $17,000,000 of 5.87% Senior Unsecured Notes, Series 2026B, due April 30, 2041 (collectively, the Notes ). The Note Purchase Agreement and the Notes collectively contain customary representations and warranties, covenants and events of default for a transaction of this type. The Notes may or will become immediately due and payable upon an event of default, as described in the Note Purchase Agreement. The foregoing summary of the Note Purchase Agreement and the Notes does not purport to be complete and is subject to, and qualified in its entirety by, the full text of such documents, the executed copies or forms of which are attached hereto as exhib','SEC EDGAR','2026-05-30T04:50:43','high');
