INSERT INTO "watchlist" VALUES(1,'CALX',11,'市场将Calix定义为一家服务于宽带运营商的传统网络设备供应商，估值受制于硬件周期与保守分析师评级。','Calix正将商业模式从硬件设备向''Calix One''云平台转型，驱动订阅收入与客户ARPU持续增长；同时主动引入Agentic AI叙事作为下一阶段增长引擎，管理层在Investor Day明确定义''下一阶段长期增长战略''。','1. 三起证券欺诈调查（Holzer & Holzer / Glancy Prongay / Frank R. Cruz）中任意一起升级为SEC正式执法行动或集体诉讼获受理，暗示Calix One增长数据存在财务披露问题。2. Q2 2026财报显示Calix One平台订阅用户增速或客户ARPU环比下滑，证明Q1案例（Fort Collins、BBT）系孤立事件而非平台级规律。','NYSE Investor Day 2026（原文明确为4月22日）上管理层首次披露Calix One平台的可量化渗透率目标、BEAD政策资金落地时间表及Private Cloud毛利率拐点数据，触发市场从''设备公司''框架向''平台SaaS公司''框架的重新定价。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(2,'CRK',11,'市场将CRK定义为业绩承压、分析师普遍给出''减持''评级的传统天然气勘探生产商','公司在西Haynesville地区选址建立电力发电中枢（Power Generation Hub），管理层正将资产从纯天然气生产向电力基础设施/AI能源供给方向重新定位；该叙事与''多万亿美元AI尾风''主题在同一时间窗口内出现。','1. 天然气价格继续下跌且库存创纪录高位（原文已出现''Natural Gas Drops on Record Storage Build''），导致西Haynesville发电中枢项目经济性恶化或被搁置；2. 分析师评级在发电中枢公告后仍维持或下调''Reduce''，说明市场未接受新叙事重定价。','西Haynesville电力发电中枢签署与AI数据中心的长期供电协议，或公布具体产能规模与投产时间表，触发市场从''天然气E&P''到''AI能源基础设施''的估值框架切换。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(3,'ORA',10,'市场将ORA定义为传统地热能源公司，以地热发电资产估值，适用偏保守的可再生能源股框架','ORA正从纯地热电力商向「地热+储能」双轮增长平台转型：80MW/320MWh Shirk储能设施已正式投入商业运营，同时签署150MW地热供电协议服务谷歌，并通过$10亿可转债大规模募资支撑扩张。','1. Q1 2026财报中储能业务收入贡献不及预期，或管理层下调全年指引；2. NV Energy/Google地热协议出现执行延迟或取消公告','Q1 2026财报电话会议（已公告即将举行）首次披露储能板块独立营收，并确认后续储能管线规模，触发市场将ORA从单一地热股重新定价为储能+地热平台股','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(4,'ARLO',9,'市场将Arlo定义为智能家居安防摄像头硬件公司，正处于向SaaS订阅模式转型阶段','Arlo通过收购Aloe Care Health将SaaS平台边界从家庭安防扩展至居家养老与健康护理新垂直赛道，同时Q4业绩超预期、订阅用户持续增长，管理层发布乐观Q1指引。','1. Q1 2026财报显示订阅用户增长停滞或下滑；2. Aloe Care Health整合受阻、无法贡献实质性收入或被剥离。','Q1 2026财报（已安排电话会议）中同步披露订阅用户加速增长 + Aloe Care Health初步营收贡献，触发市场对平台估值体系重定价。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(5,'CPK',9,'市场将CPK定义为稳健的高股息公用事业股，核心价值在于持续分红能力','公司接连任命首席转型官（Chief Transformation Officer）并更换CFO，显示管理层正主动推进战略转型而非维持现状；分红连续提升7.3%也表明现金流仍在改善。','1. 2026年5月7日Q1财报电话会议中管理层未披露转型路线图或量化目标，''转型''停留于职位名称层面；2. 后续季度分红增速逆转或归母净利润出现下滑，说明转型消耗利润而非创造价值。','2026年5月7日Q1 2026财报电话会议上，新任首席转型官首次公开阐述具体转型战略并给出可量化的财务指引，触发市场对公司成长框架的重新定价。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(6,'CNR',9,'市场将CNR（加拿大国家铁路）定义为稳健派息的北美铁路货运周期股，以货运量和成本管控驱动估值','Q1 2026业绩被管理层主动表述为''strong''，同期衍生品市场出现高成交量看涨期权，股价突破200日均线；多家机构净增持，同时有UP-NS合并重新申请的行业格局变量出现。','1. Q1 2026财报实际数据低于''strong''预期，或管理层在电话会中下调全年运营指引；2. CN月度粮食运输报告连续两期环比下滑，货运量趋势逆转。','UP-NS合并重新申请获监管批准，触发市场对北美铁路网络格局的全面重估，迫使分析师重新定价CN的竞争护城河与定价权。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(7,'WTRG',9,'市场将WTRG定义为传统高收益分红水务公用事业股，以稳定股息和监管保护为核心价值主张。','WTRG正在通过与American Water的重大合并交易实现结构性转型，该合并已获肯塔基公共服务委员会批准并通过股东大会投票，标志着公司从区域性水务运营商向全国性规模平台的质变；与此同时，公司同步推进小型市政收购（Greenville Municipal Water）和Q4盈利超预期，呈现出多线并进的增长叙事。','1. 合并交易遭遇关键监管阻力或终止，任何州级或联邦层面的否决公告均构成直接失效信号；2. Q1 2026财报确认分析师预期的盈利下滑，且管理层下调全年指引，证明增长叙事仅为并购驱动的一次性效应。','American Water与WTRG合并最终交割完成，市场将被迫用全国性规模水务平台框架重新对WTRG定价，估值倍数将向更大体量可比标的靠拢。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(8,'LZ',9,'市场将LZ定义为面临AI颠覆风险的传统在线法律文件/DIY法律服务平台，增长乏力、盈利承压。','LZ正从''AI受害者''转型为''AI基础设施使用者''：已与Anthropic（Claude）、OpenAI（ChatGPT）、GoDaddy（Open Agentic Web）达成多项AI集成合作，同时订阅业务增长依然强劲。这一转型信号在近期新闻中多次、跨平台出现。','1. Q1 2026财报（2026-05-06发布）显示订阅收入环比下滑，或AI产品无法贡献可量化收入指引；2. Anthropic/OpenAI/GoDaddy任一合作终止或降级，表明AI集成为营销噱头而非战略绑定。','2026-05-06 Q1财报超预期，且管理层首次披露AI集成（Claude/ChatGPT渠道）带来的具体订阅转化数据或收入增量，触发市场重新定价其AI平台属性。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(9,'VRRM',9,'传统交通执法与政府服务公司，依赖红灯摄像头和电子收费系统获取稳定但低增长的政府合同收入','公司一方面推出AI驱动的车载虚拟代理产品AutoKinex™，向车载数字体验赛道延伸；另一方面连续落地$9.98亿纽约市五年合同及夏威夷十年合同，政府平台规模快速扩张，同时受邀出席Morgan Stanley TMT（科技/媒体/电信）会议，暗示外部对公司定位的重新归类。','1. Q1 2026财报继续低于预期，且NYC/$998M合同收入确认节奏明显滞后于市场预期；2. AutoKinex™产品在租车行业未获实质性采购合同，停留于发布公告层面无商业化跟进。','Q1 2026财报电话会议中管理层首次披露NYC大合同收入确认进度及AutoKinex™客户签约数据，触发分析师重新建模上调目标价。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(10,'CSW',9,'市场将CSW Industrials定义为一家评级保守（平均''Hold''）的中型工业品公司，主营承包商解决方案，缺乏明确上行催化剂。','多家机构投资者在同一时间窗口密集建仓（Congress Asset Management 6500万美元、Jacobson & Schmitt 1834万美元、Allspring 140,530股），叠加公司主动将季度股息上调11%至每股0.30美元并在Q4回购3500万美元股票，内外部资本认可出现同步抬升。','1. CEO大额减持持续扩大（目前已有$430,155减持记录），或其他高管跟进卖出；2. 分析师共识评级未能从''Hold''上调，机构建仓后季度内出现减仓公告。','下一季财报（FY2027 Q1）营收/利润超预期，触发分析师从''Hold''集体上调至''Buy''，推动市场对承包商解决方案板块重新定价。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(11,'WTRG',8,'市场将WTRG定义为增长缓慢、以34年连续分红增长为卖点的传统受监管公用事业股','肯塔基公共服务委员会（PSC）已批准WTRG与美国水务公司（AWK）的合并，这是合并路径上取得的第一个监管批准，标志着一项可能从根本上改变WTRG规模与市场地位的变革性交易正在实质推进；与此同时，公司旗下子公司持续执行小型市政水务收购战略（如$18M收购Greenville Municipal Water Authority）。','1. 后续关键州（如宾夕法尼亚州）监管机构拒绝或无限期搁置AWK合并申请；2. 5月7日Q1 2026财报显示盈利跌幅超出分析师预期且管理层下调全年指引，坐实基本面恶化而非合并整合中的暂时性压力。','多个主要州监管机构相继批准AWK合并，或合并完成时间表明确公告，驱动市场将WTRG从单一公用事业股重新定价为合并后规模排名跃升的全国性水务平台。','2026-05-06',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(12,'ARLO',10,'市场将 Arlo 定义为智能家居安防摄像头硬件公司，以设备销售驱动营收','Arlo 完成收购 Aloe Care Health，将 SaaS 平台延伸至医疗警报与老年居家护理赛道；与此同时，订阅收入同比激增 39%，ARR 与付费用户数均保持 20%+ y/y 增长，公司已实质性转型为订阅服务平台。','1. Q1 2026（5月7日财报）付费订阅用户增速跌破 15% y/y，或 ARR 增长明显放缓；2. Aloe Care Health 整合后出现大额亏损且管理层下调协同预期或撤回指引。','2026年5月7日 Q1 财报发布，若订阅收入持续加速且 Aloe Care Health 贡献首次并入数字并附上盈利路径指引，将推动市场将估值框架从硬件 P/S 切换至 SaaS ARR 倍数，触发重新定价。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(13,'AGYS',10,'市场将Agilysys定义为一家专注于酒店业的传统垂直软件供应商，提供POS和物业管理系统等存量型工具。','公司在2026年INSPIRE年度用户大会上一次性推出超过30项AI驱动新功能和软件模块，会议出席人数同比增长26%创历史记录；同期公司股价单日上涨5.8%，而GF Value显示市价仍较内在价值折价约44%。','1. 2026年5月18日Q4财报显示订阅/经常性收入增速放缓或毛利率收窄，AI功能未能转化为ARR增量；2. 新客户签约节奏明显放缓（低于当前新闻中展示的澳大利亚、菲律宾、英国多地扩张态势）。','2026年5月18日Q4财报中管理层明确披露AI模块带来的新增ARR或订阅收入占比，触发分析师上调目标价并推动市价向GF Value($119.42)靠拢。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(14,'MIR',10,'市场将MIR定义为传统辐射检测与测量的''商业服务公司''（见新闻9：''both business services companies''）','管理层明确点名''核电需求引领的大幅订单增长''，叠加多家机构投资者在Q3集中大幅加仓，市场对其核能基础设施受益者身份的认知正在加速重构。','1. 订单增速在后续季度出现环比下滑，或管理层下调FY2026收入/EBITDA指引；2. 核电项目宏观端出现监管收紧或主要客户推迟资本开支的可验证公告','公司宣布与SMR/先进反应堆开发商（如X-energy等）签署大额长期供货合同，或FY2026中期业绩显示EPS同比实现显著增长（突破$0.10的同比持平瓶颈），触发分析师集体上调目标价','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(15,'ORA',10,'市场将ORA定位为利基型地热能源公用事业公司，估值参照传统可再生能源运营商框架','ORA Q1 2026实现营收75.8%同比增长至创纪录的4.039亿美元，调整后EPS跳升91.2%，增长由产品销售和储能业务驱动，同时公司已与Switch和Google等超大规模数据中心签署长期PPA，叠加10亿美元可转换票据融资完成，公司正从地热运营商向AI数据中心24/7无碳电力提供商转型。','1. 超大规模数据中心客户（Switch/Google）宣布取消或推迟PPA合同；2. 公司下调2026年全年营收或EBITDA指引','公司宣布新增一份或多份与主要超大规模数据中心的大型长期PPA合同，或EGS技术获得关键监管许可并进入商业部署阶段','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(16,'CPK',9,'市场将CPK定位为传统受监管天然气公用事业公司，核心吸引力是稳定股息收益率','CPK Q1 2026 EPS同比增长11.8%，同期董事会将季度股息提升7.3%（从$0.685至$0.735），并新设首席转型官职位；增长驱动力从单纯监管红利扩展至输气管网扩张和佛罗里达有机用户增长，公司叙事正从''高息防御股''向''成长型公用事业''迁移。','1. Q2 2026 EPS增速回落至个位数以下，或输气管网扩张项目出现监管阻碍；2. CFO Beth Cooper退休后（2026年6月30日）新领导团队下调资本投资指引或下调股息增长承诺。','分析师将CPK评级框架从''收益型公用事业''升级为''成长型公用事业''，触发机构资金重新定价——具体可观测事件为Q2 2026财报继续维持10%+EPS增速并伴随新输气管线并网公告。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(17,'HCC',9,'市场将HCC定义为一家受美国煤炭产量/消费量下滑拖累、面临多重行业挑战、值得回避的传统煤炭股','Q1 2026净利润从上年同期亏损820万美元骤升至7230万美元（EPS +1.37美元），超越分析师预期；核心增量来自Blue Creek扩产项目——该项目已提前整整8个月投产，属结构性产能跃升而非周期性波动','1. 若后续季度EPS重新回落至盈亏线附近，说明Q1利润为一次性价格脉冲而非Blue Creek产能持续贡献；2. 若分析师维持或下调评级且共识目标价不上修，说明市场已充分定价当前盈利改善','Q2 2026财报确认Blue Creek满负荷运转后EPS环比持续增长，触发多家持Hold评级的机构同步上调至Buy并提高目标价','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(18,'FSS',9,'市场将FSS定义为一家分散经营的多行业综合企业（conglomerate），归类于汽车/工业板块，估值中性、分析师覆盖有限。','FSS Q1 2026实现净销售额同比增长35%、营业利润改善52%，每股收益$1.18大幅超越一致预期$0.89（超出约33%），且较去年同期$0.76增长55%；管理层随即上调全年业绩指引并提高EBITDA利润率目标，显示盈利能力系统性跃升而非一次性。','1. Q2 2026营收增速回落至个位数或低于管理层全年指引区间，表明New Way并购贡献为一次性而非持续驱动；2. 订单积压（backlog）环比下降，或Safety and Security Systems Group EBITDA利润率未能实现上调后目标。','机构分析师基于连续两个季度超预期+上调指引将评级从''Moderate Buy''集体升至''Strong Buy''并大幅上调目标价，触发动量资金追入重新定价。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(19,'SOUN',9,'市场将SOUN定义为专注汽车和餐饮垂直领域的小众语音AI公司，股价已较高点大幅回落','公司发布OASYS平台，将自身定位从''语音AI''升级为''AI构建AI''的自学习代理AI平台，同时Q1营收创纪录达$44.2M（同比+52%），叙事框架正在发生系统性转变。此外与Richtech Robotics合作将语音代理AI嵌入机器人硬件，开辟新垂直市场。','1. 后续季度营收增速跌破30%或OASYS平台未能产生可披露的商业合同；2. Richtech Robotics合作从''非约束性意向书''阶段停滞不前，无法转化为正式协议','OASYS平台签下首个可披露的大型企业客户合同，或机器人+语音AI组合方案在餐饮/零售场景大规模部署并公布具体营收贡献','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(20,'VSEC',9,'市场仍将VSE Corporation定义为建筑/国防服务公司（部分数据源将其错误归类为''construction company''），低估其向纯航空售后市场分销与维修平台转型的战略价值','VSE已以约20.25亿美元完成对Precision Aviation Group（PAG）的收购，整合后形成横跨8国、拥有61个站点（48个维修设施）的规模化独立航空售后市场平台；同期Q1 2026营收同比增长26.8%，GAAP净利润同比增长108%，Adjusted EBITDA同比增长37.4%，增长具有连续性（Q4 2025营收同比+32%，净利润同比+114%）。','1. PAG整合出现成本超支或收入协同低于预期，导致后续季度Adjusted EBITDA增速明显回落；2. 分析师群体下调评级或目标价，股价进一步跌破52周低点$109.67。','机构投资者在5月20日B. Riley年度投资者大会后集体将VSEC重新定价为纯航空售后市场平台（而非建筑/国防标的），触发分类重构和估值体系切换。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(21,'LIF',9,'市场将Life360定义为中型市值工业/安防服务类股，与传统硬件安全公司（如ADT、REZI）归为同类','尽管股价年初至今下跌35%，Life360 FY26指引收入$640–$680M（同比增长31–39%），调整后EBITDA利润率目标20.3%，多家机构同步上调评级至买入，估值压缩与基本面背离显著扩大。','1. FY26实际收入低于指引下限$640M，或MAU增速跌破20%；2. 调整后EBITDA利润率未能如期向20.3%扩张，说明盈利改善为一次性。','FY26 Q1财报确认收入增速及EBITDA利润率双双达标，触发市场从''工业类''旧框架向''高增长SaaS+硬件平台''重新定价。','2026-05-11',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(22,'ARLO',10,'市场将 Arlo 定义为智能家居安防硬件摄像头公司，SaaS 订阅收入为早期阶段附属业务','Arlo 完成收购 AI 驱动的医疗警报与跌倒预防平台 Aloe Care Health，将平台延伸至老龄化居家护理领域；与此同时 Q4 2025 订阅收入同比激增 39%，ARR 及付费用户均保持 20% 以上增速，叙事重心正从硬件向健康科技 SaaS 迁移。','①Q1 2026 订阅收入增速明显低于 Q4 2025 的 39% 水平，或管理层下调全年 ARR 指引；②Aloe Care 整合出现实质性延迟，或收购后12个月内健康业务营收贡献在财报中未被单独披露','2026年5月7日 Q1 2026 财报电话会（已公告时间）披露 Aloe Care Health 整合后的首批订阅数据与健康服务 ARR 贡献，若同步显示订阅增速维持或加速，可能触发分析师将估值框架从硬件倍数切换至健康科技 SaaS 倍数的重定价','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(23,'HL',10,'市场将HL定义为多金属（金+银）矿业公司，受黄金价格波动影响较大，估值框架参照混合矿企。','Hecla正执行战略性资产重组，出售黄金资产（Casa Berardi已完成剥离），明确转型为纯白银公司；同时白银价格已突破历史高位且连续第六年出现供应缺口，为重新定价提供外部支撑。','1. 白银现货价格持续跌破近期支撑区间（原文提及$70为关键位），导致Q2/Q3营收指引下修；2. Nevada Midas钻探结果显示资源量低于管理层预期，或许可进度受阻，令增长故事核心驱动力消失。','Nevada Midas探区公布区域级别（district-scale）钻探结果确认资源规模，叠加机构将HL从多金属矿企重新分类至纯白银ETF持仓池，触发被动资金流入与估值倍数扩张——这一事件可在探矿结果发布后数周内可验证。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(24,'CNK',10,'CNK 被市场定义为受流媒体冲击、处于结构性衰退中的传统院线公司，长期盈利能力存疑','Zacks 将 CNK 上调至 Strong Buy（#1 排名）并将其重新定性为成长股；同期公司创下史上最高复活节五日票房纪录，Q1 每股亏损从 -$0.32 大幅收窄至 -$0.06，显示基本面改善具有连续性','Q2 2026 每股亏损相较 Q1 未见收窄甚至扩大；Summer Movie Clubhouse 参与门店覆盖率或出席数据显著低于管理层预期','2026 年夏季电影季（Summer Movie Clubhouse，6月1日至8月6日正式运营）若出席人数及票房数据超出市场预期，将提供一个具体可验证的 Q2 运营数据节点，可能触发分析师集中上调目标价并推动市场重新定价','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(25,'ROCK',9,'市场将 ROCK 视为横跨住宅建材、可再生能源与农业科技的多元化建筑产品公司','Gibraltar 正执行两步式剥离 Renewables 业务的战略重组：已将可再生能源业务重分类为''停止经营''，并以 7000 万美元现金出售 eBOS 子业务，管理层明确称此为''两步计划中的第一步''，意在将公司重塑为纯建筑产品标的。与此同时，董事会成员 James Metcalf 在 2026 年 3 月以约 40.35 美元大量内购，直接持仓增幅达 407%。','1. 第二步 Renewables 剥离交易告吹、推迟或处置对价远低于市场预期；2. 核心建筑产品业务 Q2/Q3 2026 EPS 继续大幅低于预期且管理层下调全年指引，显示剥离后的''纯净''业务本身存在结构性压力','管理层宣布完成 Renewables 两步剥离计划的''第二步''并披露具体处置对价，市场可据此对纯建筑产品 Gibraltar 重新建模定价，该事件可验证（公告时间/金额均可观测）','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(26,'AGYS',9,'服务酒店、赌场和度假村的垂直领域SaaS供应商，市场以传统POS/PMS软件公司定价框架衡量','Agilysys在2026年INSPIRE用户大会上发布超过30项AI驱动新功能，大会出席率同比增长26%；同期短期卖空量在3月单月下降22.2%，显示市场看空力量显著收缩。','1. FY2026 Q4财报显示订阅收入增速未见加速或AI相关ARR贡献被管理层定性为''未来计划''而非当期收入；2. 未来两个季度内无新增规模化客户签约公告，已公布的Deep Blue / Winford / Rudding Park等客户未见续约或扩容报道。','2026年5月18日（今日）盘后发布的FY2026 Q4财报中，若管理层在电话会议上披露AI功能相关ARR加速或新模块收入贡献的具体指引，可能触发分析师框架重估——可验证节点：财报发布后24小时内是否有分析师上调目标价并明确引用AI货币化路径。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(27,'CPK',9,'市场将CPK定义为保守型天然气公用事业公司，主要价值框架为稳定派息的收益型股票','公司新设首席转型官（Chief Transformation Officer）职位并完成任命，同时Q1 2026 EPS同比增长11.8%，超越典型公用事业增速；CFO职位由36年任期老将退休并由COO接任，暗示管理层正在推动从纯收益型向成长导向型运营模式的战略切换。','1. Q2或Q3 2026 EPS增速回落至5%以下，与传统公用事业增速无异；2. 后续财报电话会中''Chief Transformation Officer''职能及转型路线图未被主动提及，暗示该职位系PR动作而非战略实质','2026年6月30日CFO正式交接后首份季报（Q2 2026）中，新CFO Jeff Sylvester若明确量化转型战略的财务目标并维持EPS两位数增长指引，可验证事件为Q2 2026 earnings call上management guidance更新','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(28,'CXT',9,'市场将CXT定义为以货币认证/工业技术为核心的传统制造商（旧描述为''a premier industrial technology company''）','Crane NXT于2026年4月1日完成对Antares Vision的收购，将业务版图扩展至生命科学与食品饮料领域（约30亿美元市场），并同步将公司自我定位更新为''authentication and traceability technologies''全球领导者；Q1 2026同步实现6%有机销售增长并维持全年EPS指引。','1. 若后续季度有机增长率低于4%或管理层下调全年EPS指引，表明Antares Vision整合拖累核心业务；2. 若分析师覆盖数量在未来两个季度内未从7家增加，且持有评级占比未下降，说明市场分类框架未发生切换。','Q2/Q3 2026财报中Antares Vision首次并表贡献收入，若管理层在财报电话会议中上调全年EPS指引区间（当前$4.10-$4.40），可触发分析师覆盖扩展及目标价上调，构成可验证的重新定价事件。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(29,'HCC',9,'市场将HCC定义为面临行业长期衰退压力的传统冶金煤生产商，受制于煤炭需求下滑预期及周期性亏损历史','Q1 2026盈利从去年同期净亏损大幅翻转为净利润7230万美元，EPS超预期；Blue Creek矿区关键扩张项目较计划提前8个月投产，表明公司基本面可能已发生结构性改善而非仅为价格周期反弹。','若Q2 2026 EPS环比大幅下滑或重回亏损，说明Q1改善为一次性煤价反弹驱动；或Blue Creek实际产量爬坡数据显著低于管理层指引，说明提前投产的增量已被市场消化而无额外催化作用','若Q2 2026财报继续维持盈利正轨且管理层在电话会中明确上调全年产量/销量指引，可能触发分析师集中上调评级（当前7名分析师中仍有3名为Hold/Sell），形成可验证的评级重定价事件','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(30,'APPF',9,'市场将AppFolio视为传统物业管理SaaS公司，归类于房地产科技赛道中依赖按席位收费的周期性软件标的','Q1 2026业绩超预期并上调全年销售指引，同时分析师集中揭示其定价模式与单元扩张及增值服务绑定（非按席位），使其可能具备区别于传统SaaS的结构性抗周期能力；股价突破50日均线强化短期技术趋势。','全年销售指引被下调或营收增速跌破20%；增值服务收入增速持续低于核心订阅收入增速，说明定价模式分化叙事无法兑现','Q2 2026财报若再次beat-and-raise并披露增值服务收入占比环比提升，可验证平台化商业模式护城河，触发市场从''传统物业SaaS''重新定价为''房地产基础设施平台''','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(31,'SOUN',9,'市场将 SOUN 定义为专注汽车与餐饮垂直场景的小市值语音 AI 公司，属于高波动投机标的','公司于 2026 年 5 月推出 OASYS 自学习 Orchestrated Agentic AI 平台，叙事框架从「语音 AI」向「Agentic AI 构建 AI」跃迁；同期 Q1 营收 52% 增长延续 Q4 59% 增势，且通过 Richtech Robotics LOI 将触角延伸至实体机器人场景。','Q2 2026 营收增速降至 30% 以下，暗示 Q1 加速系一次性；或 OASYS 在两个季度内未见任何可披露企业级付费合同，表明产品叙事领先于实际商业变现','Q2 2026 财报（约 8 月）若 OASYS 出现首批可命名企业客户签约披露，且营收增速维持在 40%+ 以上，可能触发分析师将估值框架从「语音 AI 工具」重标为「Agentic AI 平台」','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(32,'GNTX',10,'市场将 Gentex 定义为一家成熟的汽车自动防眩镜市场领导者，增长天花板已现、高度依赖整车生产周期的传统零配件供应商。','VOXX 收购拉动 Q1 营收同比增长 17%，毛利率扩张 200bps，管理层同步上调 2026 年营收指引并将 2027 年营收指引提升至 28–29 亿美元；公司正向生物识别与智能家居安全等新品类延伸，叙事框架从''成熟零配件''向''多品类技术平台''切换，分析师开始使用''step function change''与''re-rating''措辞。','1. VOXX 收入贡献剥离后有机增速转负，说明核心镜类业务加速萎缩；2. 管理层在后续季报中下调 2027 年营收或 EPS 指引，显示当前提升系 VOXX 并表而非内生增长驱动。','若 Q2/Q3 业绩继续验证 VOXX 协同效应（有机收入保持正增长、毛利率继续扩张），且管理层在财报电话会上明确给出生物识别或智能家居新品类的量产时间表，可能触发分析师覆盖升级与估值框架重构。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(33,'ORA',10,'ORA被市场定义为小众地热电力运营商，资本密集、增长缓慢、估值偏高，属于利基可再生能源股。','Q1 2026创纪录季度：营收同比增长75.8%、调整后EPS超预期41%，产品与储能业务为核心驱动；同时与Switch、Google等超大规模数据中心客户签订长期购电协议，定位从电力供应商向AI电力基础设施提供商迁移。','1) Q2营收增速跌回个位数或管理层下调2026全年指引，说明75.8%为一次性合同堆积而非结构性加速；2) Switch或Google推迟/撤回PPA，说明数据中心需求叙事无法转化为可见合同收入。','Q2 2026财报（预计2026年8月）若Energy segment有机营收延续双位数增长，同时管理层公告新增超大规模客户PPA或EGS技术商业化里程碑，可触发分析师将ORA从公用事业框架迁移至AI电力基础设施框架重估。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(34,'GWRE',10,'市场将GWRE定义为传统P&C保险核心系统提供商，正在进行云迁移转型，增长潜力受制于保险行业缓慢的技术替换周期','Guidewire推出了ProNavigator AI助手，嵌入InsuranceSuite和InsuranceNow核心应用，显示其产品叙事可能正从''云迁移故事''转向''AI原生平台''。与此同时，RPO同比增长63%至35亿美元，客户平均新合同期限超过六年，暗示平台粘性可能正在结构性提升。','ProNavigator发布后连续两个季度内无法提供可量化的客户采用指标或AI相关收入贡献数据；RPO同比增速从63%出现明显回落或出现头部客户不续约信号','下一季度财报中ProNavigator的客户采用数据或AI附加产品ARR占比首次披露，若同步伴随全年ARR指引上调，可能触发市场对其估值框架的重新定价','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(35,'OLLI',10,'市场将OLLI定义为依赖过剩库存与破产清算机会的被动型closeout折扣零售商，业绩随供应链扰动周期性波动','OLLI''s Army忠诚会员计划增速显著，同时管理层披露创纪录的门店扩张速度并设定明确的长期门店数量目标，暗示公司可能正从机会主义折扣商向具有规模化重复客群资产的成长型零售平台转型。消费者在关税与经济压力下主动向深折扣渠道迁移，为这一转型提供结构性外部支撑。','1. 门店开业节奏实质性低于75家年度目标，或管理层在财报中下调指引；2. OLLI''s Army会员增速连续两个季度降至个位数，客单价未出现对应提升','2026财年门店净开业数可验证地达到75家目标，同时OLLI''s Army会员数增速在季报中连续披露高于20%，触发市场将其估值框架从周期性折扣商切换至具备可量化留存资产的成长零售平台','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(36,'ASTE',9,'市场将ASTE定价为传统基础设施设备制造商，依赖周期性需求、利润率薄、盈利能力受大宗成本波动压制。','Q1 2026订单积压（Backlog）同比大幅增长36.4%至5.492亿美元，显示前向需求显著改善；与此同时，股价突破200日均线，新鲜分析师覆盖开始跟进，市场认知框架可能正在切换。','Q2 2026订单积压增速回落至个位数或绝对值下降；或Investor Day上管理层未能就GAAP与Adjusted EPS之间的巨大差距（$0.06 vs $0.54）提供可验证的收敛计划。','2026年5月13日Investor Day虚拟路演，若管理层提供明确的利润率改善路径（将Adjusted EPS向GAAP EPS收敛的时间表）以及订单积压转化为收入的节奏指引，可能触发市场对盈利能力的重新定价。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(37,'AGYS',9,'市场将AGYS定义为一家服务酒店/博彩/度假村垂直行业的传统POS及物业管理软件提供商，归类于Computer-Integrated Systems。','公司在年度用户大会INSPIRE上一次性发布超过30项AI驱动新功能和软件模块，大会出席人数同比增长26%，同期多个国际新客户上线（菲律宾、澳大利亚、英国）并延伸了与FreedomPay的战略支付合作，显示AI产品化节奏与客户扩张同步加速。','Q4财报显示订阅/SaaS营收增速环比持平或下滑，表明30+AI功能未能转化为合同价值提升；或管理层在电话会中回避AI功能的具体商业化数据，将其定性为''路线图''而非已部署产品。','2026年5月18日收盘后发布的FY2026 Q4财报：若营收增速加速且管理层上调FY2027指引并明确AI功能货币化路径（如ARR/ACV提升），可能触发分析师从''Moderate Buy''向''Strong Buy''集体上调及目标价重估。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(38,'CPK',9,'市场将CPK定义为一只传统的稳定分红型天然气公用事业股，以高股息收益率为核心吸引力，增长预期有限','CPK在Q1 2026实现EPS同比增长11.8%，同期宣布季度股息提升7.3%；管理层将增长归因于''transmission expansion projects''和''regulatory initiatives''，并新设首席转型官职位，显示公司可能正从纯收益型向具备结构性增长催化剂的公用事业切换叙事框架。','1. 后续季度EPS增速跌回5%以下，表明Q1增长系一次性因素而非结构性改善；2. CFO Beth Cooper退休（2026年6月30日）后，新任CFO Jeff Sylvester首份财报出现资本支出计划下修或指引下调。','Q2 2026财报（约2026年8月）若再次确认双位数EPS增长并上调全年指引，叠加首席转型官主导的佛罗里达City Gas整合进展公开披露，可能触发分析师将覆盖框架从''dividend utility''升级为''growth utility''，带动估值重定价。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(39,'CXT',9,'市场将CXT定义为以货币防伪/工业技术为核心的传统工业科技公司（"premier industrial technology company"）','公司完成收购Antares Vision，将定位从货币鉴别切换至"全球认证与溯源技术领导者"，同时将业务版图扩展至约30亿美元规模的生命科学与食品饮料领域；Q1 2026有机销售增长6%，EPS超预期且维持全年指引，显示核心业务扩张期间基本面依然稳健。','1. Antares Vision收购后出现商誉减值或整合费用超预期，导致管理层下调全年EPS指引（低于$4.10）；2. 有机销售增速在后续两个季度明显回落（跌至低个位数），说明核心认证业务扩张动能可能不持续。','2026年Q2财报（约8月）首次披露Antares Vision收入合并贡献与协同效应量化数据，若生命科学/食品饮料溯源业务营收占比明显提升，可能触发分析师将估值框架从工业制造切换至技术平台，进而引发评级上调。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(40,'APPF',9,'市场将 AppFolio 定义为服务中小型物业管理公司的传统按席位计费 SaaS，受制于房地产周期与有限地址市场（TAM），估值框架偏向保守的成长型 SaaS 倍数。','Q1 2026 业绩超预期并上调全年营收指引，同期分析师确认其定价模型与出租单元数量挂钩而非按席位收费，使其在 SaaSpocalypse 叙事中结构性隔离；股价同步突破50日均线，技术面确认基本面改变。','全年营收指引在 Q2 财报中被下调或维持不变（而非上调）；营收增速连续两季跌破15%，表明单元扩张动能趋缓而非加速。','Q2 2026 财报若再次确认营收增速维持20%以上且全年指引再度上调，将可验证 beat-and-raise 不是一次性事件，触发分析师从「成长型 SaaS」框架向「Rule of 40 平台化公司」框架切换的集体重定价。','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(41,'SOUN',9,'市场将 SOUN 定义为专注于汽车、餐饮和企业市场的语音 AI 公司','公司于 2026 年 5 月 5 日发布 OASYS 平台，自我定位从「语音 AI」升级为「语音 + 智能体 AI」；同期 Q1 营收 $44.2M 同比增 52%，与 Richtech Robotics 签署机器人语音合作意向书，显示平台扩展意图','①连续两个季度营收增速低于 Q1 的 52%，表明增速拐点已现；②OASYS 发布后 6 个月内无可披露的付费企业客户，平台叙事无法转化为合同','2026 年 Q2 财报中 OASYS 商业合同落地（可验证：新增企业客户数或 backlog 增速加速），触发分析师从「语音 AI niche player」向「agentic AI 平台」框架切换的集中重评','2026-05-18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(42,'ARLO',11,'市场将Arlo定义为一家以智能家居安防摄像头硬件为核心、通过订阅服务附加收入的小市值消费电子公司。','Arlo完成收购AI驱动的医疗警报与跌倒预防平台Aloe Care Health，将SaaS平台从安防延伸至老龄化居家护理领域；与此同时，订阅收入同比增长39%，ARR与付费用户基础连续保持20%+增速，EBITDA与自由现金流同步扩张。','Q1 2026付费订阅用户增速跌破10% y/y；或Aloe Care整合导致运营费用大幅攀升、EBITDA转负，显示平台协同效应未能兑现。','2026年5月7日Q1财报电话会议中，若Arlo首次披露Aloe Care Health合并后的订阅收入贡献、并报告付费用户增速维持或加速，市场可能将估值框架从硬件安防公司切换至医疗健康SaaS公司，触发分析师目标价体系重置。','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(43,'ORA',11,'市场将ORA定位为传统地热能源公用事业公司，具有稳定但增长缓慢的收益特征，按公用事业估值框架定价。','ORA Q1 2026录得创纪录季度，营收同比增长75.8%（远超预期），EPS同比增长91.2%；同时与Google、Switch等超大规模数据中心签署长期PPA，并在EGS（增强型地热系统）商业化上取得实质进展，显示公司正从传统地热公用事业向AI数据中心24/7无碳基础电力供应商转型。','1) EGS项目出现可量化的商业化延迟（如2028扩容目标在季报中下修）；2) 超大规模数据中心客户（Google、Switch）公开缩减采购或取消PPA续约，可在季报及新闻稿中观测。','首个EGS商业项目正式并网发电，或公开宣布新一轮超大规模数据中心长期PPA合同（可在公司新闻稿中验证），可能触发市场将ORA从公用事业框架重新定价为AI基础设施电力供应商。','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(44,'MP',11,'市场将 MP Materials 定义为周期性稀土矿业公司，估值随大宗商品价格波动','MP Materials 正从单一矿业公司转型为涵盖采矿、精炼到磁铁制造的全链条战略工业平台，获得美国政府结构性价格底线协议支撑，且 Q4 2025 已出现正 EBITDA 拐点信号。','Magnetics Segment 连续两季度收入低于管理层指引且毛利率为负；或美国政府价格底线协议条款被修改或取消，下行保护结构性消失','即将发布的 Q1 2026 财报若首次披露 Magnetics Segment 收入并高于市场预期，可能触发分析师将估值框架从大宗商品矿商切换至工业制造商，引发目标价体系性上调','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(45,'APPF',10,'市场将 AppFolio 定义为一家传统按席位计费的物业管理 SaaS 公司，受整体软件板块估值压缩和 ''SaaSpocalypse'' 叙事拖累。','Q1 2026 业绩超预期并上调全年收入指引，同时分析师明确指出其定价模型与租赁单元扩张挂钩而非按席位收费，结构上隔离了 per-seat SaaS 风险；收入增速保持 20%+ 同时利润率持续扩张，已进入 Rule of 40 阵营。','①管理层在后续季度下调全年收入指引，或实际收入增速低于当前指引区间；②每管理单元平均收入（ARPU）连续两季度同比下滑，显示 value-added services 渗透率遭遇天花板。','Q2 2026 财报（可验证事件）若再次确认收入增速维持 20%+ 且利润率继续扩张，将可能触发市场将 APPF 从 ''SaaS 软件折价篮子'' 重新定价至 ''Rule of 40 premium 平台'' 框架，因为当前分析师共识仍存在约 38.77% 的目标价上修空间。','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(46,'KTB',10,'市场将KTB定义为以Wrangler和Lee为核心的传统工装/休闲服饰公司，Lee持续下滑拖累整体增长预期','公司宣布计划剥离Lee品牌并启动7.5亿美元股票回购，同时Helly Hansen交出优于预期的营收与盈利表现，标志着KTB正从Lee拖累的双品牌模式向Wrangler+Helly Hansen增长平台转型。全年指引同步上调。','1. Helly Hansen在Q2 2026季报中营收或盈利低于预期，表明Q1超预期为一次性；2. Lee剥离交易流产、延期或成交价显著低于市场预期，暗示资产质量差于管理层所描述','Lee品牌剥离交易正式完成并披露成交价格，若定价合理或高于预期账面价值，市场可能被迫将KTB重新定价为纯Wrangler+Helly Hansen增长平台，触发分析师覆盖框架切换与目标价上修','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(47,'GNTX',10,'市场将 GNTX 定义为依赖全球轻型车产量周期的成熟汽车自动调光后视镜制造商，估值框架以传统汽车零部件供应商为锚。','VOXX 收购带动 Q1 2026 营收同比跳升 17%，毛利率扩张 200bps，2027 年营收指引上调至 $2.8–$2.9B；同时管理层将公司定位从''后视镜供应商''向生物识别与智能家居安全延伸，有机增长在全球轻型车产量下滑背景下依然为正，分析师开始使用''re-rating''与''step function change''等语言。','① 连续两个季度毛利率回落至 VOXX 收购前水平，说明扩张依赖一次性并表效应而非结构性改善；② 中国市场收入持续双位数下滑且管理层在季报中下调 2027 指引，表明地域性逆风强度超过有机增长对冲能力。','Q2 2026 财报若在 VOXX 收入剥离/单独披露后仍显示有机毛利率维持扩张趋势，且管理层首次提供生物识别/智能家居业务的独立营收贡献数字，将为市场提供可验证的''不再是纯汽车零部件''再定价锚点。','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(48,'WTS',10,'市场将WTS定义为传统工业水处理公司，以稳健分红和周期性工业需求为估值锚点','Q1 2026创纪录业绩由数据中心需求驱动，管理层明确将AI基础设施需求列为核心增长引擎，而非仅靠定价和效率改善；此前分析师预判其无法超预期，实际EPS大幅超出共识。','管理层在Q2业绩会上将数据中心相关收入表述从''需求驱动''降级为''个别项目''或不再单独提及；或连续两个季度有机增长重回个位数且毛利率收缩','Q2 2026财报（约2026年8月）若管理层将数据中心收入单独披露或首次上调全年guidance并点名AI基础设施为驱动，可验证此thesis是否触发分析师重评级覆盖和机构重新建仓','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(49,'MIR',10,'MIR 被市场定义为服务核电、医疗、国防及研究领域的辐射探测与测量仪器供应商，属于工业传感器/仪表细分板块，而非核能基础设施股。','Q1 2026 管理层在财报中明确将''核电需求主导的订单大幅增长''列为核心亮点，核电从众多终端市场之一跃升为增长叙事主轴；与此同时，多家机构投资者在同期大幅新建或加仓，显示资金重新定位信号出现。','1. 后续季度订单增长放缓或管理层下调 FY2026 EPS 指引（当前区间 $0.50–$0.57），说明核电需求为一次性脉冲而非结构性驱动；2. 核电终端营收占比未见持续提升，医疗/国防业务权重反而上升，稀释核电叙事使重分类逻辑失效。','后续季度财报若再次确认核电订单增长加速，且管理层上调 FY2026 指引，可能触发分析师将 MIR 从''仪器仪表''板块重分类至''核能基础设施''，带动估值框架切换——此事件有明确时间点（下季度财报）且结果可验证。','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(50,'SPXC',10,'市场用「工业/建筑周期股」框架定义SPXC，将其视为与施工景气度挂钩的传统制造企业','SPXC数据中心冷却业务正从边缘分部演变为核心增长引擎，Olympus Max产品已获多年期客户承诺及大额订单，数据中心营收被预测以年化约50%的速度增长，有望在数年内由当前小份额扩张至总营收的重要占比。Q1 2026财报同步验证整体盈利能力持续超预期。','①连续两个季度数据中心相关订单增速明显放缓，或Olympus Max关键客户退出多年期承诺；②非数据中心主业营收持续下滑且管理层下调全年指引，说明数据中心增长可能是掩盖基本面恶化的短期噪音','Q2或Q3 2026财报中管理层首次在分部披露中将数据中心冷却单独列示，且该分部收入同比增速可被独立核实，触发机构投资者将SPXC从建筑股重新归类至AI基础设施赛道','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO "watchlist" VALUES(51,'ROCK',9,'市场将Gibraltar Industries定位为横跨住宅建材、农业技术与可再生能源的多元建筑制造商','公司正主动执行两步式可再生能源业务剥离战略，已将Renewables重分类为discontinued operations并以7000万美元现金出售eBOS业务；与此同时，董事会成员在二级市场大额增持，暗示内部人士认为核心业务存在重定价机会。','1. 第二步剥离长期无进展或以显著折价完成，说明Renewables资产变现能力弱于预期；2. 核心建筑产品业务连续两个季度EPS同比继续大幅下滑（Q1 2026已出现年同比约53%下降），说明剥离行动掩盖而非解锁了价值','可再生能源业务''两步剥离''第二步完成公告（即剩余Renewables资产出售），可验证时间点为管理层在Q1 2026业绩电话会或后续投资者会议中披露交割时间表','2026-05-25',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
